INSERT INTO updates (id, title, summary, date, category, tags, source_name, source_url, citation, court, blog_credit, search_tags, pinned) VALUES
  (1, 'Virginia Child Support Guidelines Expanded — Income Cap Raised to $42,500/Month (SB 805)', 'For the first time since 2014, Virginia''s Schedule of Monthly Basic Child Support Obligations was updated under Senate Bill 805, signed by the Governor on May 2, 2025, and effective July 1, 2025. The combined gross monthly income ceiling for the presumptive guidelines rose from $35,000 to $42,500, providing structured support calculations for higher-income families and replacing ad hoc judicial extrapolation. The bill also directed the Child Support Guidelines Review Panel and the Division of Child Support Enforcement to study arrearages and report recommendations to the General Assembly by November 15, 2025, including whether driver''s license suspension penalties impair obligors'' ability to pay.', '2025-07-01', 'virginia_code', '{"child_support"}', 'Virginia General Assembly / LIS', 'https://lis.virginia.gov/bill-details/20251/SB805', '2025 Va. Acts ch. 702; Va. Code § 20-108.2', NULL, 'Bowen Ten Long & Bal PC|https://btclawva.com/family-law-changes-effective-july-1-2025/', 'child_support virginia_code', FALSE),
  (2, 'Guaranteed Parental Access to Children''s Digital Academic and Medical Records (§ 20-124.6 Amendment)', 'Effective July 1, 2025, Virginia amended Code § 20-124.6 to explicitly extend the right of both custodial and non-custodial parents to access their minor child''s academic and health records to include records ''stored or accessible from a secure website.'' The amendment closed a loophole that allowed schools and healthcare providers to deny parents access to online portals for grades, attendance, immunization records, and doctor''s notes. Unlike most 2025 family law changes, this provision applied automatically to all existing custody and visitation orders on its effective date, not only to new filings.', '2025-07-01', 'virginia_code', '{"custody"}', 'Virginia General Assembly / LIS', 'https://law.lis.virginia.gov/vacodeupdates/title20/', 'Va. Code § 20-124.6 (2025)', NULL, 'Melone Hatley, P.C.|https://www.melonelawpc.com/blog/navigating-the-july-2025-family-law-changes-in-virginia/', 'custody virginia_code', FALSE),
  (3, 'Extended Protective Orders Up to Four Years; Military Protective Orders Integrated (§ 19.2-152.10 Amendment)', 'Effective July 1, 2025, Virginia doubled the maximum duration for extended protective orders from two years to four years, where the respondent had a prior protective order issued within the preceding ten years. The 2025 amendment further provides that a previously issued Military Protective Order may itself serve as a sufficient basis to issue a Preliminary Protective Order without additional evidence, and requires law enforcement to notify the military if a civil protective order is violated when a military protective order has also been issued. Courts are still limited to entering or extending orders in two-year increments under this provision.', '2025-07-01', 'virginia_code', '{"domestic_violence"}', 'Virginia General Assembly / LIS', 'https://www.cgglawyers.com/six-legal-changes-affecting-family-law-cases-in-virginia-in-2025/', 'Va. Code § 19.2-152.10 (2025); see also Va. Code § 16.1-279.1', NULL, 'Cooper Ginsberg Gray|https://www.cgglawyers.com/six-legal-changes-affecting-family-law-cases-in-virginia-in-2025/', 'domestic_violence virginia_code', FALSE),
  (4, 'Bar on Parentage Rights for Persons Who Conceived Child Through Sexual Assault (§§ 20-49.1, 20-49.2 Amendment)', 'Effective July 1, 2025, Virginia amended multiple sections of the Code — including §§ 20-49.1 and 20-49.2 — to prohibit the establishment of any parent-child relationship between a child and any person who (i) was convicted of rape, carnal knowledge, or incest, or (ii) was found by clear and convincing evidence in a civil proceeding to have committed such acts, where the child was conceived from that conduct. This bars perpetrators from seeking custody, visitation, or any legally recognized parental status, even absent a criminal conviction. The provision applies to all petitions filed on or after July 1, 2025.', '2025-07-01', 'virginia_code', '{"custody","domestic_violence"}', 'Virginia General Assembly / LIS', 'https://law.lis.virginia.gov/vacodeupdates/title20/', 'Va. Code §§ 20-49.1, 20-49.2 (2025)', NULL, 'Melone Hatley, P.C.|https://www.melonelawpc.com/blog/navigating-the-july-2025-family-law-changes-in-virginia/', 'custody domestic_violence virginia_code', FALSE),
  (5, 'Restoration of Parental Rights When Adoptive Parent Dies or Seeks Relief of Custody (§ 63.2-1517 Amendment)', 'Effective July 1, 2025, Virginia amended Code § 63.2-1517 to allow a biological parent whose parental rights were previously terminated to petition for reinstatement under four conditions: (1) the adoptive parent has died or petitioned for relief of custody; (2) the parent seeking reinstatement complied with all terms of any post-adoption contact agreement; (3) that parent consents to the restoration; and (4) that parent has maintained a positive, continuous relationship with the child since termination. The court must find reinstatement to be in the child''s best interests.', '2025-07-01', 'virginia_code', '{"adoption","guardianship"}', 'Virginia General Assembly / LIS', 'https://www.familylawva.com/key-changes-to-virginia-family-law-in-2025-what-you-need-to-know/', 'Va. Code § 63.2-1517 (2025)', NULL, 'Virginia Family Law Blog|https://www.familylawva.com/key-changes-to-virginia-family-law-in-2025-what-you-need-to-know/', 'adoption guardianship virginia_code', FALSE),
  (6, 'Stricter Appellate Deadline to Challenge Court-Ordered Home Sale During Divorce (§ 20-107.3 Amendment)', 'Effective July 1, 2025, Virginia amended Code § 20-107.3 to require parties to follow standard appellate deadlines (typically 30 days) when challenging a court-ordered sale of the marital home during divorce proceedings. Previously, parties could exploit extended timelines available for challenges to other court-ordered property sales. The amendment eliminates this ambiguity and aligns divorce property sale challenges with general appellate rules, requiring immediate action to preserve the right to contest.', '2025-07-01', 'virginia_code', '{"equitable_distribution","property_division","divorce"}', 'Virginia General Assembly / LIS', 'https://btclawva.com/family-law-changes-effective-july-1-2025/', 'Va. Code § 20-107.3 (2025)', NULL, 'Bowen Ten Long & Bal PC|https://btclawva.com/family-law-changes-effective-july-1-2025/', 'equitable_distribution property_division divorce virginia_code', FALSE),
  (7, 'Virginia Bans Child Marriage — Minimum Marriage Age Set at 18 (HB 994, 2024)', 'Effective July 1, 2024, Virginia enacted HB 994 (Chapter 737), establishing the minimum age to marry as 18 years and eliminating the prior pathway allowing a minor to be declared emancipated solely on the basis of an intent to marry. Virginia became the first Southern state and the 13th state in the nation to enact an absolute ban on child marriage. The law also repealed provisions permitting minors to seek emancipation for marriage purposes, amending §§ 16.1-241, 16.1-331, 16.1-333, 16.1-334, 20-45.1, 20-48, 20-89.1, and 20-90.', '2024-07-01', 'virginia_code', '{"divorce"}', 'Virginia General Assembly / LIS', 'https://lis.virginia.gov/bill-details/20241/HB994', '2024 Va. Acts ch. 737; Va. Code §§ 16.1-241, 20-45.1, 20-48', NULL, 'Cooper Ginsberg Gray|https://www.cgglawyers.com/8-legal-changes-affecting-family-law-cases-in-virginia/', 'divorce virginia_code', FALSE),
  (8, 'Marriage License Discrimination Based on Sex, Gender, or Race Prohibited (HB 174, 2024)', 'Effective July 1, 2024, Governor Youngkin signed HB 174, adding new § 20-13.2 to the Virginia Code, which expressly states that no clerk shall deny a marriage license based on the sex, gender, or race of the parties, and that all lawful marriages shall be recognized in the Commonwealth regardless of those factors. The law includes a religious liberty provision preserving the right of clergy to decline to perform marriages. Separately, the 2025 General Assembly passed a proposed constitutional amendment to repeal the Marshall-Newman Amendment''s same-sex marriage ban from the state constitution (which will require voter ratification).', '2024-07-01', 'virginia_code', '{"divorce"}', 'Virginia General Assembly / LIS', 'https://legiscan.com/VA/bill/HB994/2024', '2024 Va. Acts ch. 737; Va. Code § 20-13.2', NULL, NULL, 'divorce virginia_code', FALSE),
  (9, 'Adoption Process Streamlined — Hospitals May Release Newborns to Prospective Adoptive Parents Without Court Order (HB 783, 2024)', 'Effective July 1, 2024, HB 783 amended §§ 20-166, 20-167, 63.2-1201.1, and 63.2-1230 to authorize hospitals to release a newborn child to prospective adoptive parents when the birth parent has executed a health care power of attorney, eliminating the prior requirement to first obtain a separate court order (which often delayed placement by weeks). The bill also made § 63.2-1201.1 gender-neutral by removing references to ''a man and a woman,'' and shortened the hearing deadline from 45 to 10 days for entrustment agreement petitions filed by local social services boards or child welfare agencies.', '2024-07-01', 'virginia_code', '{"adoption"}', 'Virginia General Assembly / LIS', 'https://www.cgglawyers.com/8-legal-changes-affecting-family-law-cases-in-virginia/', '2024 Va. Acts ch. 737; Va. Code §§ 63.2-1201.1, 63.2-1230', NULL, 'Cooper Ginsberg Gray|https://www.cgglawyers.com/8-legal-changes-affecting-family-law-cases-in-virginia/', 'adoption virginia_code', FALSE),
  (10, 'Child Support Award Now Permitted in Protective Order Proceedings (§ 16.1-279.1 Amendment, 2024)', 'Effective July 1, 2024, Virginia amended Code § 16.1-279.1 to expressly authorize courts issuing protective orders to also award temporary child support as part of that relief. The amendment clarified that any such temporary child support award terminates upon either the determination of support pursuant to § 20-108.1 or the termination of the protective order, whichever occurs first. Separately, the 2024 session also required courts to calculate and include any support overpayments in orders establishing or modifying child or spousal support.', '2024-07-01', 'virginia_code', '{"child_support","domestic_violence"}', 'Virginia General Assembly / LIS', 'https://www.cgglawyers.com/8-legal-changes-affecting-family-law-cases-in-virginia/', 'Va. Code § 16.1-279.1 (2024)', NULL, 'Cooper Ginsberg Gray|https://www.cgglawyers.com/8-legal-changes-affecting-family-law-cases-in-virginia/', 'child_support domestic_violence virginia_code', FALSE),
  (11, 'Virginia Space Force Added to Military Parents Equal Protection Act (§§ 20-124.7, 20-108 Amendment, 2024)', 'Effective July 1, 2024, Virginia amended Code §§ 20-124.7 and 20-108 to add the United States Space Force to the list of military branches covered by the Virginia Military Parents Equal Protection Act. Previously, the Act covered the Army, Navy, Air Force, Marine Corps, Coast Guard, National Guard, and reserve components, but had not been updated since the Space Force was established in 2019. The amendment ensures that Space Force service members receive the same protections against adverse custody modifications during deployment as members of other branches.', '2024-07-01', 'virginia_code', '{"custody"}', 'Virginia General Assembly / LIS', 'https://www.cgglawyers.com/8-legal-changes-affecting-family-law-cases-in-virginia/', 'Va. Code §§ 20-124.7, 20-108 (2024)', NULL, 'Cooper Ginsberg Gray|https://www.cgglawyers.com/8-legal-changes-affecting-family-law-cases-in-virginia/', 'custody virginia_code', FALSE),
  (12, 'Relief of Custody Investigation Requirements Strengthened — Local DSS Must Refer to FAPT and File Written Report (SB 1372, 2025)', 'Effective July 1, 2025, Virginia enacted SB 1372 (Chapter 155), amending § 16.1-277.02 to require that when a parent files a petition for relief of the care and custody of a child, the local Department of Social Services (DSS) must as part of its investigation: (i) refer the parent to the local Family Assessment and Planning Team (FAPT); and (ii) create and submit a written report covering the family''s service needs, available alternatives to out-of-home placement, and other factors. DSS is directed to create a template for the report in coordination with the Virginia League of Social Services Executives. This reform came out of the Virginia Commission on Youth''s 2024 study of the statewide increase in relief-of-custody petitions.', '2025-07-01', 'virginia_code', '{"custody","guardianship"}', 'Virginia General Assembly / LIS', 'https://lis.virginia.gov/bill-details/20251/SB1372', '2025 Va. Acts ch. 155; Va. Code § 16.1-277.02', NULL, NULL, 'custody guardianship virginia_code', FALSE),
  (13, 'Virginia Parental Cannabis Use Custody Bill (HB 942) Heads to Governor Spanberger — 2026', 'In March 2026, the Virginia General Assembly passed HB 942, which provides that the lawful possession or consumption of cannabis or other legally authorized substances by a parent or guardian alone shall not serve as a basis to deny, restrict, or modify that person''s custody or visitation rights, unless other facts establish that such use is not in the best interests of the child. The bill also specifies that a parent shall not be deemed to have failed a drug test solely due to a positive result for a legally authorized substance. A substantially similar bill (HB 833) passed both chambers in 2024 and a successor (HB 2613) passed in 2025, but both were vetoed by Governor Youngkin. HB 942 now awaits action by Governor Spanberger, whose election changed the political landscape.', 'March 2026', 'virginia_code', '{"custody"}', 'Virginia General Assembly / LIS', 'https://www.marijuanamoment.net/virginia-bill-to-protect-rights-of-parents-who-use-marijuana-heads-to-governors-desk/', 'HB 942, 2026 Regular Session (pending Governor action)', NULL, NULL, 'custody virginia_code', FALSE),
  (14, 'Lisann v. Lisann — Virginia Supreme Court Clarifies ''Predominant Intent'' Standard for No-Fault Divorce Separation Period', 'On May 8, 2025, the Supreme Court of Virginia issued its opinion in Lisann v. Lisann (Record No. 230718), rejecting the Court of Appeals'' holding that the intent to permanently separate need only exist at the outset of the statutory period for no-fault divorce under Code § 20-91(A)(9). The Supreme Court held instead that the intent to permanently separate must predominate — i.e., be the prevailing and continuous intent — throughout the entire one-year (or six-month) statutory separation period. However, the Court affirmed the trial court''s divorce decree on a presumption that the circuit court applied the correct standard and that the evidence supported the wife''s continuous intent, leaving the July 14, 2014 separation date intact. The decision has direct practical impact on equitable distribution and spousal support calculations, both of which typically run from the separation date.', '2025-05-08', 'case_law', '{"divorce","equitable_distribution","spousal_support"}', 'Supreme Court of Virginia / Justia', 'https://law.justia.com/cases/virginia/supreme-court/2025/230718.html', 'Lisann v. Lisann, Record No. 230718 (Va. May 8, 2025)', 'Virginia Supreme Court', 'Virginia Family Law Journal|https://www.virginiafamilylawjournal.com/2025/12/when-separation-starts-supreme-court-pushes-back-on-appeals-court-in-lisann-v-lisann.html', 'divorce equitable_distribution spousal_support case_law Virginia Supreme Court', FALSE),
  (15, 'Schmidt v. Deel — Virginia Supreme Court Holds Unpaid Child Support in Separation Agreement Is Enforceable as Contract Claim', 'On April 24, 2025, the Supreme Court of Virginia reversed the Court of Appeals in Schmidt v. Deel (Record No. 240264), holding that a mother could pursue unpaid child support under a parties'' 2012 separation agreement as a breach of contract claim, not merely as a statutory arrearage claim limited by Code § 20-108.2(B)''s retroactivity restriction to the petition date. The Court found the circuit court''s award was properly grounded in contract principles, and that the child''s third-party beneficiary claim may allow recovery back to the agreement''s 2012 execution date due to tolling provisions for minors, subject to the five-year statute of limitations for written contracts. The case was remanded for determination of attorney fees.', '2025-04-24', 'case_law', '{"child_support"}', 'Virginia Appellate Law Blog', 'https://virginiaappeals.org/2025/04/24/schmidt-v-deel-record-no-240264-va-apr-24-2025-unpub/', 'Schmidt v. Deel, Record No. 240264 (Va. Apr. 24, 2025) (unpub.)', 'Virginia Supreme Court', 'Blankingship & Keith, PC|https://www.blankingshipandkeith.com/news-insights/supreme-court-clarifies-unpaid-child-support-can-be-pursued-as-contractual-claims', 'child_support case_law Virginia Supreme Court', FALSE),
  (16, 'Jorge Guevara-Martinez v. City of Alexandria — Virginia Court of Appeals Reverses Premature Termination of Parental Rights', 'On October 1, 2024, the Virginia Court of Appeals reversed a circuit court''s termination of a Honduran father''s parental rights under Code § 16.1-283(C)(2), holding that the Department of Community and Human Services failed to present clear and convincing evidence that the father was unfit or had failed to remedy the conditions requiring foster care placement. The court emphasized that past conduct justifying initial foster care placement cannot substitute for proof of ongoing unfitness, and that the Department failed to provide the father — who could not legally enter the United States for years — a meaningful opportunity to undergo rehabilitation once he arrived in Virginia. The court reversed and remanded, reaffirming the high evidentiary threshold required before permanently severing the parent-child relationship as a constitutionally protected fundamental right.', '2024-10-01', 'case_law', '{"custody","guardianship"}', 'Virginia Court of Appeals / Justia', 'https://law.justia.com/cases/virginia/court-of-appeals-unpublished/2024/1848-22-4.html', 'Jorge Guevara-Martinez v. City of Alexandria Dep''t of Community & Human Services, Record No. 1848-22-4 (Va. Ct. App. Oct. 1, 2024)', 'Virginia Court of Appeals', 'Smith Strong, PLC|https://www.smithstrong.com/library/parental-rights-wrongfully-terminated-virginia-court-of-appeals-reverses-termination.cfm', 'custody guardianship case_law Virginia Court of Appeals', FALSE),
  (17, 'Gonzalez v. Sarmiento — Virginia Court of Appeals: Equitable Distribution Jurisdiction Expires 21 Days After Divorce Decree', 'In Gonzalez v. Sarmiento (VLW 025-7-247), the Virginia Court of Appeals held that a circuit court had lost jurisdiction to equitably distribute the parties'' marital home because the husband failed to seek equitable distribution within 21 days of entry of the 2019 divorce order and the court had not retained jurisdiction in the decree. Although the husband attempted to reframe his claim as a separate constructive trust action against a third party (his wife''s father who held title), the court found the substance of the claim was equitable distribution under Code § 20-107.3, and the 21-day window had elapsed. The decision reinforces the strict jurisdictional deadline for raising equitable distribution claims after divorce.', '2025-09-30', 'case_law', '{"equitable_distribution","property_division","divorce"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2025/09/30/virginia-divorce-property-jurisdiction-expired/', 'Gonzalez v. Sarmiento, VLW 025-7-247 (Va. Ct. App. 2025)', 'Virginia Court of Appeals', NULL, 'equitable_distribution property_division divorce case_law Virginia Court of Appeals', FALSE),
  (18, 'Heidemann v. Heidemann — Virginia Circuit Court Rules Human Embryos Are Not Subject to Partition Under Virginia Law', 'On March 7, 2025, Fairfax County Circuit Court Judge Dontae L. Bugg dismissed a post-divorce partition action concerning two frozen embryos, holding that human embryos are not ''goods or chattels'' subject to partition under Virginia Code §§ 8.01-83 or 8.01-93. The court rejected the prior judge''s 2023 opinion that analogized embryos to partitionable personal property, finding that the legislature''s removal of references to slaves from the partition statute was evidence that human beings and entities with the potential for human life should not be subject to that statute. The court noted that partition in kind is inherently impractical for unique biological entities, and that ordering a sale is ''neither legally sanctioned nor ethically acceptable'' under Virginia law, suggesting the General Assembly address the legal framework for embryo disposition.', '2025-03-07', 'case_law', '{"equitable_distribution","property_division","divorce"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2025/03/24/domestic-relations-human-embryos-arent-subject-to-partition-under-virginia-law/', 'Heidemann v. Heidemann, Case No. CL-2023-8845 (Fairfax Cty. Cir. Ct. Mar. 7, 2025) (VLW 025-8-013)', 'Virginia Circuit Court (Fairfax County)', NULL, 'equitable_distribution property_division divorce case_law Virginia Circuit Court (Fairfax County)', FALSE),
  (19, 'Davidson/Neblett v. Neblett — Virginia Court of Appeals: Court''s Child Support Jurisdiction Not Waived by Property Settlement Agreement Requiring Material Change Showing', 'On March 25, 2025, the Virginia Court of Appeals affirmed the circuit court''s initial child support order in a same-sex adoptive parent divorce, holding that a PSA provision stating ''neither party shall pay child support … absent a showing of a material change in circumstances'' did not bind the court where the divorce decree had not been finalized as to parenting issues when the PSA was executed, and the child support hearing was therefore an initial — not a modification — proceeding. The court applied the best-interests-of-the-child standard rather than the change-in-circumstances standard, affirming a $536.30/month award plus retroactive arrears. The decision underscores that parents cannot contract away a court''s jurisdiction to set child support for the first time.', '2025-03-25', 'case_law', '{"child_support"}', 'Virginia Court of Appeals / Justia', 'https://law.justia.com/cases/virginia/court-of-appeals-unpublished/2025/2096-23-3.html', 'Davidson v. Neblett, Record No. 2096-23-3 (Va. Ct. App. Mar. 25, 2025)', 'Virginia Court of Appeals', NULL, 'child_support case_law Virginia Court of Appeals', FALSE),
  (20, 'United States v. Rahimi — SCOTUS Upholds Federal Ban on Firearms for Individuals Under Domestic Violence Protective Orders', 'On June 21, 2024, the U.S. Supreme Court ruled 8-1 in United States v. Rahimi (No. 22-915) that 18 U.S.C. § 922(g)(8) — which makes it a federal crime for a person subject to a domestic violence civil protective order to possess a firearm — is consistent with the Second Amendment. Writing for the majority, Chief Justice Roberts held that when an individual has been found to pose a credible threat to the physical safety of another person, the Constitution permits temporary disarmament. The decision is directly relevant to family law practitioners because it validates the enforcement mechanism behind civil protective orders in domestic violence cases, reinforcing that protective orders carry real federal firearm consequences for respondents.', '2024-06-21', 'supreme_court_us', '{"domestic_violence"}', 'U.S. Supreme Court', 'https://www.supremecourt.gov/opinions/23pdf/22-915_8o6b.pdf', 'United States v. Rahimi, 602 U.S. ___ (2024) (No. 22-915)', 'SCOTUS', 'SCOTUSblog|https://www.scotusblog.com/2024/06/supreme-court-upholds-bar-on-guns-with-domestic-violence-restraining-orders/', 'domestic_violence supreme_court_us SCOTUS', FALSE),
  (21, 'United States v. Skrmetti — SCOTUS Upholds State Bans on Gender-Affirming Care for Minors Against Equal Protection Challenge', 'On June 18, 2025, the Supreme Court ruled 6-3 in United States v. Skrmetti (No. 23-477) that Tennessee''s Senate Bill 1 — which prohibits healthcare providers from administering puberty blockers or hormones to minors for the purpose of gender transition — does not violate the Equal Protection Clause of the Fourteenth Amendment. The majority held that SB1 classifies on the basis of age and medical diagnosis, not sex or transgender status, and therefore need only satisfy rational basis review, which it passes. The decision validates similar bans in approximately 25 states, while leaving open due process challenges brought by parents arguing the laws override their right to make healthcare decisions for their children. The ruling has significant implications for interstate custody disputes involving transgender minors and parental relocation across state lines.', '2025-06-18', 'supreme_court_us', '{"custody"}', 'U.S. Supreme Court', 'https://www.supremecourt.gov/opinions/24pdf/23-477_2cp3.pdf', 'United States v. Skrmetti, 606 U.S. ___ (2025) (No. 23-477)', 'SCOTUS', 'KFF|https://www.kff.org/lgbtq/what-are-the-implications-of-the-skrmetti-ruling-for-minors-access-to-gender-affirming-care/', 'custody supreme_court_us SCOTUS', FALSE),
  (22, 'Mahmoud v. Taylor — SCOTUS Holds Parents Have First Amendment Right to Opt Children Out of LGBTQ+ Instructional Materials', 'On June 27, 2025, the Supreme Court ruled 6-3 in Mahmoud v. Taylor (No. 24-297) that Montgomery County, Maryland''s school district violated the Free Exercise Clause of the First Amendment by revoking parents'' ability to opt their children out of storybooks with LGBTQ+ themes that conflicted with their religious beliefs. Writing for the majority, Justice Alito applied strict scrutiny to the school board''s policy, finding it substantially burdened religious exercise and failed to satisfy that standard. The decision establishes a nationwide requirement that public schools must accommodate sincere religious opt-out requests from parents when curriculum covers controversial topics like gender identity, and is directly relevant to Virginia family law practitioners handling disputes over children''s school placements and parental religious upbringing rights.', '2025-06-27', 'supreme_court_us', '{"custody"}', 'U.S. Supreme Court', 'https://www.supremecourt.gov/opinions/24pdf/24-297_4f14.pdf', 'Mahmoud v. Taylor, No. 24-297 (U.S. June 27, 2025)', 'SCOTUS', 'Oyez|https://www.oyez.org/cases/2024/24-297', 'custody supreme_court_us SCOTUS', FALSE),
  (23, 'Mirabelli v. Bonta — SCOTUS Emergency Order Bars California from Hiding Children''s Gender Transitions from Parents', 'On March 2, 2026, the U.S. Supreme Court issued an emergency 6-3 order in Mirabelli v. Bonta (No. 25A810) vacating the Ninth Circuit''s stay and reinstating a permanent injunction that prohibits California schools from concealing a student''s gender transition from parents without the child''s consent. The majority held that California parents were likely to succeed on both Free Exercise and Substantive Due Process grounds, emphasizing that the state''s non-disclosure policy ''cut out the primary protectors of children''s best interests: their parents.'' The decision cited Mahmoud v. Taylor and reaffirmed that parents hold primary authority over their children''s upbringing and mental health decisions. As a shadow docket ruling, it does not create binding precedent but signals how the Court would likely rule on the merits.', '2026-03-02', 'supreme_court_us', '{"custody"}', 'Cornell Law School / LII', 'https://www.law.cornell.edu/supremecourt/text/25A810', 'Mirabelli v. Bonta, 607 U.S. ___ (2026) (No. 25A810)', 'SCOTUS', 'SCOTUSblog|https://www.scotusblog.com/2026/03/divided-court-sides-with-parents-in-dispute-over-california-policies-on-transgender-students/', 'custody supreme_court_us SCOTUS', FALSE),
  (24, 'Virginia Court of Appeals Affirms Equitable Distribution and Spousal Support in Pope v. Pope', 'On June 24, 2025, the Virginia Court of Appeals issued its opinion in Pope v. Pope, affirming the Stafford County Circuit Court''s rulings on equitable distribution, spousal support, and attorney fees on all issues, rejecting each of the appellant''s claims. The court concluded that the trial judge properly applied the law in all respects. While the case is not further reported, the complete victory for the appellee represents a significant affirmance of circuit court methodology in complex equitable distribution and spousal support disputes involving multiple assets and contested valuation.', '2025-06-24', 'case_law', '{"equitable_distribution","spousal_support","divorce"}', 'Blankingship & Keith, PC', 'https://www.blankingshipandkeith.com/news-insights/blankingship-keiths-juli-m-porto-prevails-in-virginia-court-of-appeals-secures-complete-appellate-victory-in-divorce-case', 'Pope v. Pope (Va. Ct. App. June 24, 2025)', 'Virginia Court of Appeals', 'Blankingship & Keith, PC|https://www.blankingshipandkeith.com/news-insights/blankingship-keiths-juli-m-porto-prevails-in-virginia-court-of-appeals-secures-complete-appellate-victory-in-divorce-case', 'equitable_distribution spousal_support divorce case_law Virginia Court of Appeals', FALSE),
  (25, 'Virginia Court of Appeals: Frozen Embryo Disposition Uses Balancing Test Weighing Procreational Autonomy of Both Spouses (Jessee)', 'In a significant published decision (arising from the Jessee circuit court case), the Virginia Court of Appeals declined to resolve whether a frozen pre-embryo constitutes marital property subject to equitable distribution — the parties and circuit court had already agreed it did — and instead focused on the constitutional rights of both parties to procreate or not procreate. The Court adopted a balancing test giving judges broad discretion to weigh factors relevant to procreational autonomy rather than an all-or-nothing contemporaneous mutual consent or contract approach. Factors courts must consider include whether either party already has children, the parties'' ages and health, and other circumstances bearing on reproductive interests. This framework continues to govern embryo disposition in Virginia divorce cases unless and until the General Assembly legislates.', '2024-10-01', 'case_law', '{"equitable_distribution","property_division","divorce"}', 'Virginia State Bar — Family Law Quarterly', 'https://vsb.org/common/Uploaded%20files/sections-conferences/_CurrentNewsletterIssues/fa-current.pdf', 'Jessee v. Jessee (Va. Ct. App. 2024) (following 866 S.E.2d 46 (Va. Ct. App. 2021))', 'Virginia Court of Appeals', NULL, 'equitable_distribution property_division divorce case_law Virginia Court of Appeals', FALSE),
  (26, 'LEO 1901: Reasonable Fees and the Use of Generative Artificial Intelligence', 'On November 24, 2025, the Supreme Court of Virginia approved Legal Ethics Opinion 1901, addressing how attorneys may ethically charge for work assisted by generative AI. The opinion holds that Rule 1.5 does not require lawyers to reduce non-hourly fees proportionally when AI reduces time spent, because AI use elevates the skill required (prompting, verifying outputs, identifying hallucinations). Virginia''s approach diverges from ABA Formal Opinion 512 (2024) and North Carolina Formal Ethics Opinion 1 (2024), which suggested downward fee adjustments for AI efficiency gains. Attorneys must still adequately explain fees to clients and verify all AI outputs for accuracy.', '2025-11-24', 'ethics_opinion', '{"ethics","ai_in_law","technology","competence","fees"}', 'Virginia State Bar – Legal Ethics Opinions', 'https://vsb.org/Site/Site/news/RulesFiltered/rule-changes-typefilter-leo.aspx', NULL, NULL, 'Virginia Lawyers Weekly – ''Legal ethics opinion provides guidance on billing for AI use''|https://valawyersweekly.com/2025/07/13/virginia-legal-ethics-ai-value-billing/', 'ethics ai_in_law technology competence fees ethics_opinion', FALSE),
  (27, 'LEO 1900: Duty to Disclose the Death of a Client', 'On January 4, 2024, the Supreme Court of Virginia adopted Legal Ethics Opinion 1900, establishing that a lawyer must disclose a client''s death to opposing counsel before any further substantive communication and to a court no later than the next communication or appearance. The opinion is grounded in Rules 4.1 (truthfulness with others) and 3.3 (candor toward the tribunal), as the attorney-client relationship terminates automatically upon death. LEO 1900 expressly overrules prior LEO 952, which had permitted acceptance of a settlement offer without disclosing the client''s death absent a direct health inquiry. The opinion clarifies that an attorney cannot accept or make a settlement offer on behalf of a deceased client until an estate representative is appointed and retains the lawyer.', '2024-01-04', 'ethics_opinion', '{"ethics","confidentiality","competence","malpractice"}', 'Virginia State Bar – Legal Ethics Opinion 1900', 'https://vsb.org/common/Uploaded%20files/LEOs/1900.pdf', NULL, NULL, 'National Law Review – ''Virginia Supreme Court Rules Lawyers Must Disclose Client''s Death''|https://natlawreview.com/article/disclosure-upon-death-client-under-virginia-supreme-court-legal-ethics-opinion-1900', 'ethics confidentiality competence malpractice ethics_opinion', FALSE),
  (28, 'Rule of Professional Conduct 1.5(g) Amended: Nonrefundable Advanced Legal Fees Prohibited', 'Effective July 15, 2025, the Supreme Court of Virginia amended Rule 1.5 of the Rules of Professional Conduct to add subsection (g), stating that ''nonrefundable advanced legal fees are prohibited.'' The amendment codifies longstanding guidance from prior Legal Ethics Opinions (including LEO 1606 and LEO 1899), making explicit that advance payments are client property held in trust and earned only upon services rendered. Two new comments were added: Comment 10 addresses the client''s right to terminate representation and Comment 11 distinguishes a true retainer (earned upon receipt for availability) from an advanced legal fee (which remains refundable until earned). Attorneys must revise fee agreements to remove nonrefundable clauses and ensure flat-fee arrangements include milestones for earning fees.', '2025-05-16', 'court_rules', '{"ethics","trust_accounts","fees","advertising"}', 'Virginia State Bar – Rule Changes (Adopted)', 'https://vsb.org/Site/Site/news/RulesFiltered/rule-changes-typefilter-rules-adopt.aspx', NULL, NULL, 'Virginia Lawyers Weekly – ''Supreme Court of Virginia bars nonrefundable advanced legal fees''|https://valawyersweekly.com/2025/06/01/virginia-bans-nonrefundable-legal-fees-rule-change/', 'ethics trust_accounts fees advertising court_rules', FALSE),
  (29, 'Rule of Professional Conduct 6.5 Amended: Limited Legal Services Programs', 'Effective July 15, 2025, the Supreme Court of Virginia amended Rule of Professional Conduct 6.5 to clarify that attorneys providing court-appointed short-term limited legal services (including first appearances and same-day bail hearings) are not required to conduct a conflict check before representation. The VSB Council approved the proposed rule in a 54-2 vote on March 1, 2025. The amendment was developed in response to a 2023 Joint Legislative Audit and Review Commission report recommending study of limited representation at first appearances and bail hearings, aiming to ''reduce administrative burdens while maintaining ethical safeguards.''', '2025-05-16', 'court_rules', '{"ethics","conflicts","competence"}', 'Virginia State Bar – Rule Changes (Adopted): Rule 6.5', 'https://vsb.org/Site/Site/news/rules-news/20241122-rule-6.5-limited-legal-services-programs.aspx', NULL, NULL, 'Virginia Lawyers Weekly – ''Supreme Court of Virginia approves rule amendment on limited legal services''|https://valawyersweekly.com/2025/05/29/virginia-rule-6-5-amendment-limited-legal-services/', 'ethics conflicts competence court_rules', FALSE),
  (30, 'Part 6 § IV Paragraph 13 Amended: Attorney Discipline Procedure Rules Strengthened', 'Effective December 1, 2025, the Supreme Court of Virginia approved amendments to Part 6, Section IV, Paragraph 13 of the Rules of the Supreme Court of Virginia governing attorney discipline procedures. Key changes include: (1) granting Bar Counsel the same mechanism and deadlines as respondents to elect a three-judge circuit court panel for disciplinary proceedings, conforming to Va. Code § 54.1-3935.A; (2) clarifying that a three-judge panel substituting for a district committee may impose suspension or revocation; and (3) aligning board and district committee procedures for considering a respondent''s disciplinary record. The amendment also changes district committee language from ''may'' to ''must'' impose sanctions when misconduct is found, and eliminates restrictions on terms when a suspension exceeds one year. The VSB petitioned for this change following a 58-1 Council vote on June 12, 2025.', '2025-10-02', 'court_rules', '{"disciplinary","technology"}', 'Virginia State Bar – Rule Changes: Part 6 Section IV Paragraph 13', 'https://vsb.org/DC/Site/news/rules-news/20250410-prop-para-13.aspx', NULL, NULL, 'Virginia Lawyers Weekly – ''Supreme Court of Virginia approves amendment to attorney discipline rule''|https://valawyersweekly.com/2025/10/07/virginia-attorney-discipline-rule-amendment/', 'disciplinary technology court_rules', FALSE),
  (31, 'Proposed Amendment to Rule 1.5(d): Contingent Fees in Domestic Relations Cases', 'In March 2025, the VSB posted a proposed amendment to Rule 1.5(d) that would remove the longstanding strict prohibition on contingent fees in domestic relations matters. Under the proposal, contingent fees would be permitted in domestic relations cases subject only to the general reasonableness standard of the remainder of Rule 1.5, with no additional restrictions. The Virginia Trial Lawyers Association Family Law Section submitted public comment on the proposal in May 2025. As of February 28, 2026, the VSB Council had not yet voted on this amendment, but it was referenced as a pending rule change.', '2025-03-27', 'court_rules', '{"ethics","fees","advertising"}', 'Virginia State Bar – Proposed Rule 1.5(d) Amendment', 'https://vsb.org/Site/Site/news/rules-news/20250327-rule-1.5-fees.aspx', NULL, NULL, NULL, 'ethics fees advertising court_rules', FALSE),
  (32, 'Proposed Amendment to RPC 1.9(c): Former Client Conflict – Criminal History Exception', 'In March 2025, the VSB sought public comment on a proposed amendment to Rule 1.9(c) of the Rules of Professional Conduct. The amendment would permit a lawyer to use information gained during representation of a former client to that former client''s disadvantage when the information ''consists solely of criminal history information that can be obtained from law enforcement databases or court records.'' On February 28, 2026, the VSB Council approved the amendment (46 yes, 17 no, 1 abstention), and the petition was submitted to the Supreme Court of Virginia on March 9, 2026 for final approval.', '2026-02-28', 'court_rules', '{"ethics","conflicts","confidentiality"}', 'Virginia State Bar – VSB Council February 28, 2026 Meeting Highlights', 'https://vsb.org/Site/news/news-items/20260228-bc-meeting.aspx', NULL, NULL, 'Virginia Lawyers Weekly – ''Bar seeks comment on amendment to conflict of interest rule''|https://valawyersweekly.com/2025/04/03/bar-seeks-comment-on-amendment-to-conflict-of-interest-rule/', 'ethics conflicts confidentiality court_rules', FALSE),
  (33, 'Supreme Court of Virginia Amends Rules 1A:8 and 3C:2 (Military Spouse Admission; Uniform Fine Schedule)', 'On October 2, 2025, the Supreme Court of Virginia amended Rules 1A:8 (Military Spouse Provisional Admission) and 3C:2 (Uniform Fine Schedule). Rule 3C:2 took effect immediately, while Rule 1A:8 became effective December 1, 2025. The Rule 1A:8 amendment updates the provisional admission process for military spouses licensed in other jurisdictions, which is relevant to attorneys in Virginia''s military-heavy communities (Northern Virginia, Hampton Roads). The Uniform Fine Schedule amendment addresses fines applicable in circuit courts.', '2025-10-02', 'court_rules', '{"technology"}', 'Virginia State Bar – Supreme Court Amends Rules 1A:8 and 3C:2', 'https://vsb.org/Site/news/news-items/20251002-SCV-rules.aspx', NULL, NULL, NULL, 'technology court_rules', FALSE),
  (34, 'Supreme Court Amends Multiple Rules of Court (August 2025): Rules 3:8, 4:7, 5:5, 5:30, 5:38, 5A:3, 5A:23, 5A:36', 'Effective August 17, 2025, the Supreme Court of Virginia amended eight rules governing civil and appellate procedure, including Rules 3:8 (answers, pleas, and motions), 4:7 (use of depositions), 5:5 and 5A:3 (filing deadlines and extensions), 5:30 and 5A:23 (amicus curiae briefs), and 5:38 and 5A:36 (mediation and settlement of pending appeals). An additional set of civil and appellate procedural rules (Rules 1:24, 3:17, 4:1, 4:9A, 5:1, 5A:1, 5A:6, 5A:27, 7C:5) was also amended effective July 1, 2025. These amendments reflect ongoing court administration improvements following the 2022 expansion of the Court of Appeals of Virginia''s jurisdiction.', '2025-06-18', 'court_rules', '{"technology"}', 'Virginia State Bar – Supreme Court Amends Rules 3:8, 4:7, 5:5, 5:30, 5:38, 5A:3, 5A:23, 5A:36', 'https://vsb.org/Site/Site/news/news-items/20250620-SCV-rules.aspx', NULL, NULL, NULL, 'technology court_rules', FALSE),
  (35, 'VSB Technology and Future Practice of Law Committee Releases 2025 Report', 'The VSB Special Committee on Technology and the Future Practice of Law released its 2025 annual report at the VSB Annual Meeting in Virginia Beach on June 13, 2025. The report addresses how AI—particularly generative AI—is reshaping legal practice, including impacts on the billable hour, document drafting, legal research, and client communication. Key conclusions include that AI will likely accelerate a shift from purely hourly billing toward hybrid flat-fee and value-based models for automatable tasks, while strategic lawyering (court appearances, negotiations, case strategy) will retain the billable hour. The committee, composed of lawyers with legal technology expertise, also noted that AI''s integration will increase, not decrease, required lawyer skill to properly configure, supervise, and verify AI outputs.', '2025-06-13', 'vsb_update', '{"ai_in_law","technology","competence","ethics"}', 'Virginia State Bar – Technology and Future Practice of Law 2025 Report', 'https://vsb.org/common/Uploaded%20files/docs/pub-future-law-report-2025.pdf', NULL, NULL, 'Virginia Lawyer (VSB) – ''VSB Technology and the Future Practice of Law Committee Releases 2025 Report''|https://virginialawyer.vsb.org/articles/vsb-technology-and-the-future-practice-of-law-committee-releases-2025-report', 'ai_in_law technology competence ethics vsb_update', FALSE),
  (36, 'VSB Releases EGAD Report: 57% Decline in Bar Examinees, ''Legal Desert'' Crisis', 'In December 2025, the VSB released its final Report on Entry, Growth, and Distribution of Virginia Attorneys (EGAD), representing nearly two years of committee work. The report found a 57% decline in Virginia Bar Exam takers from 2012 to 2024—far exceeding the national 15% decline—attributed largely to the lack of Uniform Bar Exam (UBE) portability. The report identified 44% of Virginia''s 133 localities as ''legal deserts'' (fewer than 1 attorney per 1,000 residents) and 73% as ''private practice deserts.'' It documented a 31% decline in qualified guardians ad litem since 2020, a 25% drop in private practice attorneys since 2010, and aging attorney demographics in rural areas. The report''s 30 recommendations include adopting NextGen UBE, expanding loan forgiveness for rural practice, and developing alternative licensure pathways.', '2025-12-02', 'vsb_update', '{"technology","competence"}', 'Virginia State Bar – EGAD Report Release', 'https://vsb.org/Site/Site/news/news-items/20251202-EGAD-report.aspx', NULL, NULL, NULL, 'technology competence vsb_update', FALSE),
  (37, 'VSB Seeks Legislative Activity to Increase Guardian Ad Litem Compensation', 'On January 14, 2026, the Supreme Court of Virginia approved the VSB''s petition to support legislative activity during the 2026 General Assembly Session to increase compensation for guardians ad litem (GALs) serving children and incapacitated adults. The VSB sought to align the GAL in-court hourly rate (then $57.50/hour out of court) with rates for court-appointed counsel in criminal defense and child dependency matters. The petition was prompted by a 31% decline in qualified GAL attorneys since 2020, cited in the Children''s Ombudsman''s 2025 report as partly attributable to low compensation. The proposed 2026 budget amendment would provide $1.5 million annually from the general fund for the rate increase.', '2026-01-14', 'vsb_update', '{"ethics","competence"}', 'Virginia State Bar – Supreme Court Approves VSB Request re: GAL Compensation', 'https://vsb.org/Site/Site/news/news-items/20251110-vsb-comment-legislative-activity.aspx', NULL, NULL, NULL, 'ethics competence vsb_update', FALSE),
  (38, 'Virginia Board of Bar Examiners Adopts NextGen Bar Exam Format for July 2028', 'In December 2024, the Virginia Board of Bar Examiners (VBBE) announced its decision to adopt the NextGen Bar Exam, developed by the National Conference of Bar Examiners (NCBE), replacing the Multistate Bar Examination (MBE) which NCBE will discontinue after February 2028. Virginia''s first NextGen administration will be in July 2028. The new 9-hour exam (administered over 1.5 days) will be paired with a retained Virginia-specific essay component (3 hours or less) testing state law. In April 2025, the VBBE released additional details on content and format. The NextGen exam tests nine areas of law including family law, plus seven foundational lawyering skills and attorney ethics integrated throughout.', '2024-12-11', 'vsb_update', '{"competence","technology"}', 'Virginia Board of Bar Examiners – NextGen Bar Exam Announcement', 'https://vsb.org/Site/Site/news/news-items/20241211-VBBE-nextgen-2028.aspx', NULL, NULL, NULL, 'competence technology vsb_update', FALSE),
  (39, 'VSB February 2026 Council Meeting: RPC 1.9(c) and Unauthorized Practice Amendments Approved', 'At the February 28, 2026 VSB Council meeting in Roanoke, the Council approved two significant rule change petitions to forward to the Supreme Court of Virginia: (1) amendments to RPC 1.9(c) on former client conflicts (allowing use of publicly available criminal history information), approved 46-17-1; and (2) amendments to unauthorized practice rules under Part 6, Section I, Paragraph 3(O), approved 46-13-1. The Council also approved the FY2027 VSB budget (64-1) and revised bylaws for 11 bar sections effective immediately. The MCLE Board reported revisions to regulations and opinions effective May 1, 2026. Reports were also received from the Technology and Future Practice of Law Committee and the EGAD-VA Study Committee.', '2026-02-28', 'vsb_update', '{"ethics","conflicts","technology"}', 'Virginia State Bar – Highlights of February 28 VSB Council Meeting', 'https://vsb.org/Site/news/news-items/20260228-bc-meeting.aspx', NULL, NULL, NULL, 'ethics conflicts technology vsb_update', FALSE),
  (40, 'Attorney Discipline: Shalonda Michelle Tillman License Revoked for Trust Account Misconduct', 'Effective November 3, 2025, the Virginia State Bar Disciplinary Board revoked the law license of Shalonda Michelle Tillman of Virginia, based on her affidavit consenting to revocation acknowledging that material facts underlying five pending disciplinary proceedings (Docket Nos. 24-021-131347, 25-021-133958, 25-021-133202, 25-021-133530, 25-021-135200) were true. Court records and prior reporting confirm the misconduct involved inaccurate trust account record-keeping resulting in the misappropriation of client funds. Trust account violations of this nature typically implicate Rules 1.15 (Safekeeping Property) and 8.4 (Misconduct).', '2025-11-03', 'attorney_discipline', '{"trust_accounts","disciplinary","malpractice"}', 'Virginia State Bar – Shalonda Michelle Tillman Revocation', 'https://vsb.org/Site/Site/news/summary/20251105-tillman.aspx', NULL, NULL, 'ALABnews – ''Attorney Shalonda Michelle Tillman''s License Revoked in Virginia Over Trust Account Issues''|https://alabnews.com/attorney-shalonda-michelle-tillmans-license-revoked-in-virginia-over-trust-account-issues/', 'trust_accounts disciplinary malpractice attorney_discipline', FALSE),
  (41, 'Attorney Discipline: Robert Lubin License Revoked; Board of Immigration Appeals Suspension Follows', 'Effective October 24, 2025, the Virginia State Bar Disciplinary Board revoked the law license of Robert Lubin of Reston, Virginia, based on his affidavit consenting to revocation while misconduct allegations were pending. Following the Virginia revocation, on December 18, 2025, the Board of Immigration Appeals granted a petition for Lubin''s immediate suspension from practice before the BIA, Immigration Courts, and the Department of Homeland Security, pending final disposition of proceedings. This case illustrates how state bar discipline triggers reciprocal federal agency consequences for attorneys in specialized practice areas.', '2025-10-24', 'attorney_discipline', '{"disciplinary","malpractice"}', 'Virginia State Bar – Robert Lubin Revocation', 'https://vsb.org/Site/Site/news/summary/20251028-lubin.aspx', NULL, NULL, 'ALABnews – ''Attorney Robert Lubin Suspended from Immigration Practice Following Revocation of Virginia License''|https://alabnews.com/attorney-robert-lubin-suspended-from-immigration-practice-following-revocation-of-virginia-license/', 'disciplinary malpractice attorney_discipline', FALSE),
  (42, 'Attorney Discipline: Marlene Alice Harris Suspended Six Months for Diligence, Communication, and Termination Failures', 'Effective March 21, 2026, the Virginia State Bar Disciplinary Board suspended Marlene Alice Harris of Midlothian, Virginia for six months for violating professional rules governing diligence (Rule 1.3), communication (Rule 1.4), and declining or terminating representation (Rule 1.16). This was an agreed disposition. The diligence, communication, and termination violations are among the most commonly charged rules in VSB disciplinary proceedings and are directly relevant to family law and general civil practitioners who face high client-contact and deadline-driven practice demands.', '2025-09-16', 'attorney_discipline', '{"disciplinary","competence","malpractice"}', 'Virginia State Bar – Marlene Alice Harris Suspension', 'https://vsb.org/Site/news/summary/20250916-harris.aspx', NULL, NULL, 'Virginia Lawyers Weekly – ''VSB Disciplinary Actions: Sept. 22 Issue''|https://valawyersweekly.com/2025/09/22/vsb-disciplinary-actions-sept-22-issue/', 'disciplinary competence malpractice attorney_discipline', FALSE),
  (43, 'Attorney Discipline: Jared Ryan Jenkins Suspended Nine Months – ''Scurrilous Statements'' Against Judge Affirmed by Supreme Court', 'In November 2024, the Supreme Court of Virginia affirmed a three-judge panel''s decision to suspend attorney Jared Ryan Jenkins for nine months and impose monetary sanctions for violating Rules 3.4 (Fairness to Opposing Party) and 8.3 (Reporting Professional Misconduct). Jenkins, acting on behalf of trust beneficiaries in Rockbridge County circuit court trust litigation, made statements impugning the integrity of the circuit court judge and refused to pay $4,000 in opposing counsel sanctions ordered under Va. Code § 8.01-271.1. The Supreme Court, writing through Justice McCullough, rejected Jenkins'' argument that the court lacked jurisdiction to sanction him and that a favorable appellate ruling would retroactively justify his conduct. The case is Jenkins v. Virginia State Bar (VLW 024-6-036).', '2024-11-04', 'attorney_discipline', '{"disciplinary","malpractice","competence"}', 'Virginia Lawyers Weekly – ''Scurrilous Statements: Supreme Court Affirms Attorney''s Suspension''', 'https://valawyersweekly.com/2024/11/04/scurrilous-statements-supreme-court-affirms-attorneys-suspension/', NULL, NULL, NULL, 'disciplinary malpractice competence attorney_discipline', FALSE),
  (44, 'Attorney Discipline: David Blair Mintz Summarily Suspended Following Maryland Disbarment', 'Effective October 22, 2025, the Virginia State Bar Disciplinary Board summarily suspended David Blair Mintz of Columbia, Maryland''s Virginia law license, based on his disbarment from practice in Maryland by the Supreme Court of Maryland dated September 4, 2025. Mintz was ordered to appear before the VSB Disciplinary Board on November 14, 2025 to show cause why the same discipline should not be imposed in Virginia. Effective November 14, 2025, Mintz''s Virginia license was revoked. This case illustrates Virginia''s reciprocal discipline process under Part 6 of the Rules of the Supreme Court of Virginia.', '2025-10-22', 'attorney_discipline', '{"disciplinary","malpractice"}', 'Virginia State Bar – David Blair Mintz Suspension', 'https://vsb.org/Site/news/summary/20251022-mintz.aspx', NULL, NULL, 'Virginia Lawyers Weekly – ''VSB Disciplinary Actions: Nov. 3 Issue''|https://valawyersweekly.com/2025/11/02/vsb-disciplinary-actions-nov-3-issue/', 'disciplinary malpractice attorney_discipline', FALSE),
  (45, 'Attorney Discipline: VSB Clients'' Protection Fund Pays $266,994 on 18 Petitions – Trust Account and Unearned Fees Cases', 'At its November 7, 2024 meeting, the VSB Clients'' Protection Fund Board authorized payments totaling $266,994.00 to reimburse former clients harmed by four Virginia attorneys whose licenses were suspended or revoked. Notable cases include attorney Steven Biss, whose clients were awarded up to $100,000 each (the Fund''s maximum per petitioner) after Biss failed to deposit escrow funds totaling over $253,000 into his trust account; attorney Dale Reese Jensen (license revoked October 2023), who generated $14,999 in unearned fee awards for former clients in criminal matters; and attorney David Gary Hoffman (license revoked December 2021), whose former client recovered $13,420 for estate planning services never rendered. These cases highlight recurring trust account and unearned fee violations.', '2025-04-01', 'attorney_discipline', '{"trust_accounts","disciplinary","malpractice"}', 'Virginia Lawyer (VSB) – April 2025: Clients'' Protection Fund Report', 'https://virginialawyer.vsb.org/april-2025/page-44', NULL, NULL, NULL, 'trust_accounts disciplinary malpractice attorney_discipline', FALSE),
  (46, 'Attorney Discipline: Timothy R. King – Public Reprimand for Fees and Safekeeping Property Violations', 'Effective July 3, 2025, the Virginia State Bar Fifth District, Section II Subcommittee issued a public reprimand with terms to Timothy R. King for violating professional rules governing fees (Rule 1.5) and safekeeping of property (Rule 1.15). This was an agreed disposition. Trust account and fee violations remain among the most common grounds for VSB discipline, particularly for family law and general practice attorneys who routinely handle client funds for retainers, settlements, and guardian-related matters.', '2025-07-03', 'attorney_discipline', '{"trust_accounts","disciplinary","fees"}', 'Virginia State Bar – Disciplinary System Actions', 'https://vsb.org/Site/Site/news/disciplinary-actions.aspx', NULL, NULL, 'Virginia Lawyers Weekly – ''VSB Disciplinary Actions: July 14 Issue''|https://valawyersweekly.com/2025/07/13/vsb-disciplinary-actions-july-14-issue/', 'trust_accounts disciplinary fees attorney_discipline', FALSE),
  (47, 'VSB Disciplinary Conference 2025: 43rd Annual Meeting on Attorney Discipline', 'The Virginia State Bar held its 43rd Annual Disciplinary Conference at Virginia Crossings Hotel in Richmond on July 31 – August 1, 2025. The conference focuses on education and professional development for VSB disciplinary district committee members, disciplinary board members, and bar counsel on procedural and substantive developments in the attorney discipline system. The timing follows the June 2025 rule amendments and aligns with preparation for implementation of the December 2025 Part 6 Paragraph 13 amendments strengthening disciplinary procedures.', '2025-07-31', 'vsb_update', '{"disciplinary","ethics"}', 'Virginia State Bar – 43rd Annual Disciplinary Conference Agenda', 'https://vsbwebstorage.blob.core.windows.net/$web/BarServices/Discipline/2025DiscConfAgenda_May%202025.pdf', NULL, NULL, NULL, 'disciplinary ethics vsb_update', FALSE),
  (48, 'Virginia Family Law Statute Changes Effective July 1, 2025: Child Support, Protective Orders, Parental Rights', 'Effective July 1, 2025, several significant amendments to Virginia''s family law statutes took effect with direct implications for family law practitioners. Child support guidelines under Va. Code § 20-108.2 were expanded to apply to combined gross monthly incomes up to $42,500 (up from $35,000), potentially increasing payments by 10-20% for mid-to-high income families. Protective order durations were extended to up to four years (from two years) when the respondent has a prior protective order within the past 10 years under Va. Code § 19.2-152.10, with new integration of military protective orders as admissible evidence. A new provision bars individuals convicted of rape, carnal knowledge, or incest from establishing a parent-child relationship with children conceived from such acts under Va. Code § 20-49.2. Home sale appeals in divorce proceedings now follow standard appellate timelines.', '2025-07-01', 'court_rules', '{"ethics","competence"}', 'Virginia Family Law Blog – ''Key Changes to Virginia Family Law in 2025''', 'https://www.familylawva.com/key-changes-to-virginia-family-law-in-2025-what-you-need-to-know/', NULL, NULL, NULL, 'ethics competence court_rules', FALSE),
  (49, 'VSB Seeks Public Comment on Rule 1.5 Amendments Regarding Fees (August 2024)', 'In August 2024, the Virginia State Bar sought public comment on a proposed amendment to Rule 1.5 (Fees) that would add a new paragraph (g) and new comments [10] and [11] addressing nonrefundable advanced legal fees. This public comment period was the precursor to the Supreme Court of Virginia''s May 2025 amendment that formally prohibited nonrefundable advanced legal fees effective July 15, 2025. Separately, in the same period, the VSB also sought comment on providing free legal billing software to members as a revenue-and-cost-neutral service.', '2024-08-30', 'vsb_update', '{"ethics","fees","trust_accounts"}', 'Virginia State Bar – News and Resources', 'https://vsb.org/Site/Site/05_News-and-resources/bar-news.aspx', NULL, NULL, NULL, 'ethics fees trust_accounts vsb_update', FALSE),
  (50, 'VSB Disciplinary Public Hearing Docket Active Through April 2026', 'The VSB''s publicly available disciplinary hearing docket as of March 2026 shows hearings scheduled into April 2026, including a scheduled April 13, 2026 misconduct hearing for Philip Loyd Bradfield (Newport News) in Henrico County Circuit Court. The VSB publishes upcoming public disciplinary hearings to provide transparency in the discipline process. The active docket reflects the ongoing pace of VSB misconduct proceedings following the December 2025 amendments that strengthened the discipline procedure rules.', '2026-03-13', 'attorney_discipline', '{"disciplinary"}', 'Virginia State Bar – Public Disciplinary Hearings Docket', 'https://vsb.org/common/Uploaded%20files/docs/vsb-docket-hearing.pdf', NULL, NULL, NULL, 'disciplinary attorney_discipline', FALSE),
  (51, 'Pew Research: 8 Facts About Divorce in the United States', 'Pew Research Center''s October 2025 analysis of federal data finds that the refined U.S. divorce rate fell to 14.4 per 1,000 married women in 2023, down sharply from 20.5 in 2008 and a peak of 22.6 in 1980. Over 1.8 million Americans divorced in 2023, and one-third of ever-married Americans have experienced divorce. Two-thirds of those who divorced have gone on to remarry, and divorced working-age adults have a median household wealth of $98,700 — less than a third of the $326,900 median for adults in their first marriage.', '2025-10-16', 'study', '{"divorce","demographics","financial","marriage"}', 'Pew Research Center', 'https://www.pewresearch.org/short-reads/2025/10/16/8-facts-about-divorce-in-the-united-states/', NULL, NULL, NULL, 'divorce demographics financial marriage study', FALSE),
  (52, 'CDC FastStats: 2022 U.S. Marriage and Divorce Rates', 'The CDC National Center for Health Statistics reports that in 2022, there were 2,041,926 marriages in the United States (a rate of 6.1 per 1,000 total population) and 672,502 divorces across 45 reporting states and D.C. (a rate of 2.4 per 1,000 population). Virginia''s provisional divorce rate stands at 2.7 per 1,000 population, above the national average. These CDC FastStats represent the most current national vital statistics data.', '2025-03-17', 'study', '{"divorce","marriage","demographics"}', 'Centers for Disease Control and Prevention (CDC), National Center for Health Statistics', 'https://www.cdc.gov/nchs/fastats/marriage-divorce.htm', NULL, NULL, NULL, 'divorce marriage demographics study', FALSE),
  (53, 'U.S. Census Bureau: Fewer Than Half of U.S. Households Are Married Couples in 2025', 'The U.S. Census Bureau''s December 2025 release of America''s Families and Living Arrangements data finds that only 47% of U.S. households in 2025 are married couples, down from 66% in 1975. The median age at first marriage has risen to 30.8 for men and 28.4 for women — up from 23.5 and 21.1 in 1975. The share of married-couple households with their own children under 18 declined from 54% to 37% over the same fifty-year span.', '2025-12-02', 'study', '{"marriage","demographics","parenting_time"}', 'U.S. Census Bureau', 'https://www.census.gov/newsroom/press-releases/2025/families-and-living-arrangements.html', NULL, NULL, NULL, 'marriage demographics parenting_time study', FALSE),
  (54, 'BGSU National Center for Family & Marriage Research: U.S. Refined Marriage Rate Remains Stable in 2024', 'The National Center for Family & Marriage Research at Bowling Green State University reports the U.S. refined marriage rate held steady at 31.2 women marrying per 1,000 unmarried women in 2024, with over 2.39 million women marrying — a nominal increase of 29,452 from 2023. Utah led all states for a fifth consecutive year at 51.7 per 1,000, while Delaware was lowest at 20.1. The Northeast region had the lowest marriage rates nationally, with 78% of its states falling in the bottom quartile.', '2025-10-09', 'study', '{"marriage","demographics"}', 'National Center for Family & Marriage Research, Bowling Green State University', 'https://www.bgsu.edu/ncfmr/resources/data/family-profiles/FP-25-30.html', NULL, NULL, NULL, 'marriage demographics study', FALSE),
  (55, 'Census Bureau Data: U.S. Divorce Rate Declined 28% From 2012 to 2022', 'A U.S. Census Bureau analysis using American Community Survey data reveals the national divorce rate fell 28% between 2012 and 2022, dropping to 7 new divorces per 1,000 women. However, 14 states — concentrated in the South and Mountain West — continue to show divorce rates ''significantly higher'' than the national average, with Arkansas leading at 11.9 per 1,000 women. Virginia was not among the significantly higher states, though the broader divorce landscape shows pronounced regional disparities. The marriage rate remained stable over the same period except for a COVID-related dip in 2021.', '2025-10-08', 'news', '{"divorce","demographics"}', 'U.S. Census Bureau / The Hill', 'https://thehill.com/homenews/5541298-divorce-rates-significantly-higher-in-these-states-census-bureau-says/', NULL, NULL, NULL, 'divorce demographics news', FALSE),
  (56, 'Pew Research: Divorce Rate at Historic Low in 2023 as Millennials Drive Stability', 'A Pew Research analysis of Census Bureau data finds the U.S. divorce rate reached a historic low in 2023, with only 1.4% of married adults divorcing that year. Professor Philip Cohen of the University of Maryland attributes the decline to Millennials and Generation X marrying later and more selectively than previous generations. The report notes a corresponding increase in partnered adults — 51% of U.S. adults were married in 2023, up slightly from 50% in 2019, and the share of single adults fell from 44% to 42%.', '2025-01-17', 'news', '{"divorce","marriage","demographics"}', 'Pew Research Center', 'https://www.pewresearch.org/short-reads/2025/10/16/8-facts-about-divorce-in-the-united-states/', NULL, NULL, 'KOMO News Fact Check Team|https://komonews.com/news/nation-world/divorce-rates-hit-record-low-in-the-us-as-marriage-trends-shift-census-data-generation-x-millenials-relationships', 'divorce marriage demographics news', FALSE),
  (57, '''Gray Divorce'' Rate Among Adults 50+ Has Tripled Since 1990s While Overall Rates Fall', 'Research from Bowling Green State University and Purdue University documents that while the overall U.S. divorce rate is at multi-decade lows, divorce among adults 65 and older reached 15% in 2022 — triple the rate from the 1990s. For adults 50 and older, over one-third of all divorces now occur in this age group, and the divorce rate rose from 3.9 to 11.0 per 1,000 married women ages 50+ between 1990 and 2008. Pew Research Center notes the gray divorce rate stabilized at 10.3 per 1,000 in 2023. Women are more likely than men to initiate gray divorces, partly due to increased financial independence and changing societal expectations.', '2025-03-11', 'trend', '{"divorce","demographics","financial","mental_health"}', 'Purdue University / Bowling Green State University / Pew Research Center', 'https://www.purdue.edu/hhs/news/2025/03/purdue-expert-overall-divorce-rates-lowest-in-decades-but-gray-divorce-soars/', NULL, NULL, NULL, 'divorce demographics financial mental_health trend', FALSE),
  (58, 'NBER Study: Parental Divorce Has Substantial Long-Term Negative Impacts on Children', 'An August 2025 NBER working paper (No. 33776) by Johnston, Jones, and Pope — tracking over 5 million children born 1988–1993 through federal tax, Census, and Social Security records — finds that parental divorce causes significant long-term harm to children. Divorce before age 5 is associated with a 63% increase in teen birth rates, a 35–55% increase in child mortality, a 43% higher probability of incarceration by adulthood, and a 40% decline in college residency rates. Adult earnings at age 27 are reduced by 3.9 income percentile points. The researchers identify household income loss, neighborhood quality decline, and greater physical distance from non-resident parents as key mechanisms.', '2025-08-01', 'study', '{"divorce","child_welfare","parenting_time","mental_health","financial"}', 'National Bureau of Economic Research (NBER)', 'https://www.nber.org/digest/202508/parental-divorce-and-childrens-long-term-outcomes', NULL, NULL, NULL, 'divorce child_welfare parenting_time mental_health financial study', FALSE),
  (59, 'NBER Working Paper: Joint Custody Laws Reduce Interstate Migration of Separated Fathers by 11 Percentage Points', 'A December 2025 NBER working paper (No. 34571) by Adams, Bayraktar, Jørgensen, Low, and Voena finds that joint child custody laws causally reduce interstate migration of separated fathers by 11 percentage points, using the staggered adoption of joint custody statutes across U.S. states. Migration of separated fathers has fallen significantly more than for married fathers. For mothers, joint custody had no impact on mobility but showed suggestive evidence of beneficial labor market outcomes. The findings document a major, underappreciated constraint that custody arrangements impose on parental geographic mobility.', '2025-12-15', 'study', '{"custody","parenting_time","coparenting","relocation"}', 'National Bureau of Economic Research (NBER)', 'https://www.nber.org/papers/w34571', NULL, NULL, NULL, 'custody parenting_time coparenting relocation study', FALSE),
  (60, 'Penn State Study: Coparenting Quality During COVID-19 Had Long-Term Effects on Family Well-Being', 'A peer-reviewed study published in the Journal of Family Psychology (February 2025) by Conway and Feinberg at Penn State examined 150 parents from a ten-year longitudinal study. Over half of parents reported a decline in coparenting quality during the initial COVID-19 pandemic stage. Families that maintained or improved coparenting quality showed lower parental hostility, fewer depressive symptoms, and greater family cohesion 19 months later. Positive coparenting changes reduced internalizing symptoms in female children and improved parenting behaviors for families with younger children.', '2025-02-01', 'study', '{"coparenting","mental_health","child_welfare","parenting_time"}', 'Journal of Family Psychology (American Psychological Association) / PubMed Central', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC11887928/', NULL, NULL, NULL, 'coparenting mental_health child_welfare parenting_time study', FALSE),
  (61, 'American Family Survey 2025: Growing American Indifference Toward Marriage as an Institution', 'The 11th Annual American Family Survey (2025), a nationwide poll of 3,000 Americans by BYU''s Wheatley Institute and Deseret News, finds that only 45% of Americans agree society is better off when more people are married, down from 53% in 2018. Support for marriage across key metrics — financial stability, strong family formation, societal benefit — has declined by roughly 10 percentage points since 2018 across both political parties. More than 7 in 10 Americans (71%) say raising children is now unaffordable, a 13-point jump in a single year, suggesting economic pressures are driving reduced marriage intent.', '2025-11-14', 'study', '{"marriage","demographics","financial"}', 'BYU Wheatley Institute / Deseret News / American Family Survey', 'https://wheatley.byu.edu/family/american-family-survey-2025-american-families-in-an-era-of-rapid-change', NULL, NULL, NULL, 'marriage demographics financial study', FALSE),
  (62, 'National Parents Organization 2025 Shared Parenting Report Card: Most States Still Fail to Protect Children''s Access to Both Parents', 'The National Parents Organization''s 2025 Shared Parenting Report Card — updating its 2019 analysis — grades all 50 states and D.C. on statutory provisions that promote equal shared parenting after separation. Only 6 states earned an ''A'' grade; 10 states and D.C. received ''B''s; 19 states earned ''C''s; 14 received ''D''s; and 2 states received ''F''s. The report finds that despite a strong and growing research consensus supporting legal presumptions of shared parenting for children''s outcomes, most state legislatures have taken no significant steps toward such reforms.', '2025-01-01', 'study', '{"custody","parenting_time","coparenting","child_welfare"}', 'National Parents Organization', 'https://www.sharedparenting.org/2025-shared-parenting-report-card', NULL, NULL, NULL, 'custody parenting_time coparenting child_welfare study', FALSE),
  (63, 'WHO Global Report: 840 Million Women Have Experienced Partner or Sexual Violence', 'A landmark November 2025 World Health Organization report — the most comprehensive global study on intimate partner and non-partner sexual violence — estimates that nearly 1 in 3 women (840 million globally) have experienced partner or sexual violence in their lifetime, a figure that has barely changed since 2000. In the past 12 months alone, 316 million women (11% of those aged 15+) were subjected to physical or sexual violence by an intimate partner. The annual rate of decline is only 0.2%, and the report warns that funding for violence prevention programs has collapsed, with only 0.2% of global development aid directed toward such programs in 2022.', '2025-11-19', 'study', '{"domestic_violence"}', 'World Health Organization (WHO)', 'https://www.who.int/news/item/19-11-2025-lifetime-toll--840-million-women-faced-partner-or-sexual-violence', NULL, NULL, NULL, 'domestic_violence study', FALSE),
  (64, 'Virginia Domestic and Sexual Violence 2024 Annual Report', 'The Virginia Office of the Attorney General''s 2024 Annual Report on Domestic and Sexual Violence documents that in 2023, there were 72,831 calls to Virginia''s Statewide Hotline for Domestic and Sexual Violence. Domestic violence and sexual assault agencies provided 230,759 nights of emergency or temporary shelter for 5,700 adults and children, and delivered in-person advocacy to 28,814 individuals. In CY 2024, the OAG Victim Services Team supported 694 victims; 26% involved domestic/sexual violence cases and 23% involved child victims of sexual abuse or assault. The state conducted 10 protective order trainings reaching 531 clerks of court.', '2025-01-01', 'study', '{"domestic_violence","child_welfare"}', 'Virginia Office of the Attorney General', 'https://rga.lis.virginia.gov/Published/2025/RD61', NULL, NULL, NULL, 'domestic_violence child_welfare study', FALSE),
  (65, 'Virginia Sexual & Domestic Violence Action Alliance: 2024 VAdata Report', 'The Virginia Sexual & Domestic Violence Action Alliance''s 2024 VAdata Report finds that Virginia''s 70 domestic and sexual violence agencies answered 68,641 hotline contacts in 2024 — a 13% decline from the 2022 peak of 78,964. Agencies sheltered 3,237 adults and 2,312 children totaling 232,601 shelter nights, but denied 1,083 requests due to capacity — a 120% increase in unmet shelter demand since 2020. Transitional housing nights reached a five-year high of 105,070. Over 19% of survivors reported weapon use by a perpetrator, and more than 25% faced threats of homicide or suicide.', '2025-08-01', 'study', '{"domestic_violence","child_welfare"}', 'Virginia Sexual & Domestic Violence Action Alliance', 'https://vsdvalliance.org/wp-content/uploads/2025/08/VAdata-report-2024-4.pdf', NULL, NULL, NULL, 'domestic_violence child_welfare study', FALSE),
  (66, 'NNEDV 2024 Domestic Violence Counts Report: Virginia Snapshot', 'The National Network to End Domestic Violence''s 19th Annual DV Counts Report (2025) surveyed Virginia programs on September 4, 2024. Of 66 identified Virginia domestic violence programs, 56 (85%) participated. During the 24-hour survey period, programs served 1,422 victims, provided 1,360 hotline contacts (averaging 57 per hour), and educated 442 community members through 22 sessions. Programs could not fulfill 121 service requests — approximately 45% of which were for emergency shelter or housing — due to insufficient funding and capacity.', '2025-05-19', 'study', '{"domestic_violence","child_welfare"}', 'National Network to End Domestic Violence (NNEDV)', 'https://nnedv.org/wp-content/uploads/2025/05/19th%20Annual%20Domestic%20Violence%20Counts%20Report%20-%20Summary%20B%20Virginia.pdf', NULL, NULL, NULL, 'domestic_violence child_welfare study', FALSE),
  (67, 'Virginia''s 2025 Family Law Overhaul: Child Support, Protective Orders, and Custody Rights', 'Effective July 1, 2025, Virginia enacted sweeping family law changes under Senate Bill 805 and related legislation. Child support guidelines were expanded for the first time since 2014, raising the combined gross monthly income threshold from $35,000 to $42,500. Protective order durations doubled from two to four years (for respondents with prior orders within 10 years), with military protective orders now admissible in civil proceedings. Courts were given explicit authority to bar individuals who conceived children through rape, incest, or carnal knowledge from obtaining parental rights, regardless of criminal conviction. Both parents also received explicit statutory rights to access children''s academic and health records through digital portals.', '2025-07-01', 'news', '{"custody","child_welfare","domestic_violence","financial","parenting_time"}', 'Virginia General Assembly', 'https://www.cgglawyers.com/six-legal-changes-affecting-family-law-cases-in-virginia-in-2025/', NULL, NULL, NULL, 'custody child_welfare domestic_violence financial parenting_time news', FALSE),
  (68, 'Virginia CDC Divorce Rate: 2.7 Per 1,000 Population', 'The CDC''s National Center for Health Statistics State Stats data shows Virginia''s provisional divorce rate at 2.7 divorces per 1,000 population — above the national average of 2.4. Virginia''s rate places it among the upper-middle tier nationally, tied with Washington state, Maryland, and North Carolina. The state''s significant military presence in Norfolk, Hampton Roads, and Northern Virginia is a recognized contributing factor to elevated divorce rates due to deployments, relocations, and associated financial stress.', '2025-08-20', 'study', '{"divorce","demographics"}', 'CDC National Center for Health Statistics — Stats of the States', 'https://www.cdc.gov/nchs/state-stats/more-maps/divorce.html', NULL, NULL, NULL, 'divorce demographics study', FALSE),
  (69, 'Virginia SB 1372 (2025): Child Welfare Custody Investigation Reform', 'Virginia Senate Bill 1372, signed into law on March 19, 2025 (Chapter 155, effective July 1, 2025), requires local departments of social services — upon referral of a request for relief of care and custody of a child — to refer the parent to the local family assessment and planning team and produce a written investigation report using a standardized state template. The bill directs the Office of the Children''s Ombudsman to convene a stakeholder workgroup to study evidence standards for temporary relief of custody and report findings by November 1, 2025. The bill passed both chambers unanimously.', '2025-03-19', 'news', '{"child_welfare","custody"}', 'Virginia General Assembly', 'https://legiscan.com/VA/bill/SB1372/2025', NULL, NULL, NULL, 'child_welfare custody news', FALSE),
  (70, 'National Child Support Enforcement: $31 Billion Collected in FY 2023', 'The National Child Support Enforcement Association''s June 2024 Quick Facts report shows that the federal-state Child Support Program collected $31 billion in FY 2023 across 12 million cases serving 12.7 million children — a return of $4.37 for every $1 in public funds invested. Income withholding orders accounted for 70% of all collections. A 2022 NCSEA study found that gig work is more prevalent among parents owing child support than other workers, creating ongoing compliance challenges. Wisconsin data illustrates that approximately 4,000 child support obligors per year have driver''s licenses suspended due to nonpayment.', '2024-06-29', 'study', '{"financial","child_welfare","custody"}', 'National Child Support Enforcement Association (NCSEA)', 'https://www.ncsea.org/wp-content/uploads/2024/07/Quick-Facts-Child-Support-Enforcement-2024.pdf', NULL, NULL, NULL, 'financial child_welfare custody study', FALSE),
  (71, 'Debt.com Survey: Debt-Related Divorces Rose From 29% to 42% Between 2023 and 2025', 'Debt.com''s fourth annual Debt and Divorce survey (2025) reveals that debt-related divorces surged from 29% to 42% of all divorces between 2023 and 2025. Generation Z was most affected, with half of Gen Z respondents admitting to hiding financial burdens from partners; 38% believed credit card debt is a valid reason for divorce. Nearly 70% of all respondents agreed that concealing debt constitutes ''financial infidelity.'' Among divorced respondents, 20% reported still struggling to achieve both financial and emotional stability post-divorce.', '2025-10-07', 'study', '{"divorce","financial","demographics"}', 'Debt.com', 'https://www.yahoo.com/lifestyle/articles/survey-finds-shocking-between-debt-160000148.html', NULL, NULL, 'Yahoo Finance / Men''s Journal|https://www.yahoo.com/lifestyle/articles/survey-finds-shocking-between-debt-160000148.html', 'divorce financial demographics study', FALSE),
  (72, 'Peer-Reviewed Study: Parental Divorce Impairs Children''s Moral Adjustment, Educational Outcomes', 'A 2025 study published in the journal Behavioral Sciences (PMC12024015) finds a moderate, positive correlation between moral maturity and divorce adjustment difficulty in children who experienced parental loss or divorce. Children of divorce showed elevated scores on conflict, maladjustment, depression, and anxiety dimensions, and below-average social support scores. Gender, educational level, and substance use were significant predictors of moral maturity outcomes. The authors emphasize that professional support programs and family communication strategies are essential to promote adjustment in affected children.', '2025-04-16', 'study', '{"divorce","child_welfare","mental_health"}', 'Behavioral Sciences (MDPI) / PubMed Central', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC12024015/', NULL, NULL, NULL, 'divorce child_welfare mental_health study', FALSE),
  (73, 'USAFacts: U.S. Marriage and Divorce Trends — Racial and Ethnic Disparities (2024 Data)', 'A February 2025 USAFacts analysis of Census data finds that in 2024, 47.1% of U.S. households were headed by married couples — the second lowest share recorded. The share of divorced men rose from 2.0% in 1950 to 8.4% in 2024, and from 2.4% to 10.8% for women. Marriage rates have declined across all racial and ethnic groups except Asian Americans, who maintain the highest marriage rate at approximately 61% for both men and women. Black men and women continue to have the lowest marriage rates nationally — 37.8% and 33.3% respectively in 2024.', '2025-02-11', 'study', '{"marriage","divorce","demographics"}', 'USAFacts', 'https://usafacts.org/articles/state-relationships-marriages-and-living-alone-us/', NULL, NULL, NULL, 'marriage divorce demographics study', FALSE),
  (74, 'Virginia Poverty Law Center: Child Welfare Reform in Focus — Gaps in Prevention and Accountability', 'A January 2026 Virginia Poverty Law Center report highlights persistent gaps in Virginia''s child welfare system following a recent state review. The review identified ongoing deficiencies in prevention services and accountability mechanisms, even as proposed reforms are under consideration. The analysis calls for stronger state oversight and more robust early intervention to reduce unnecessary child removals and improve outcomes for families involved with the child welfare system.', '2026-01-23', 'news', '{"child_welfare","custody"}', 'Virginia Poverty Law Center', 'https://www.vplc.org/news/child-welfare-reform-in-focus/', NULL, NULL, NULL, 'child_welfare custody news', FALSE),
  (75, 'AAML 2025 Annual Meeting: Key Trends and Advocacy for Family Law Associates', 'The American Academy of Matrimonial Lawyers (AAML) held its 2025 Annual Meeting and Institute for Family Law Associates, with sessions addressing best practices for balancing strong client advocacy with evolving ethical standards in family law. AAML continues to serve as the premier organization for board-certified family law specialists, tracking legislative and judicial trends nationally. The 2025 Institute sessions addressed the growing complexity of custody evaluations, financial disclosure in high-asset divorces, and managing high-conflict cases in family court.', '2025-07-18', 'news', '{"custody","divorce","financial"}', 'American Academy of Matrimonial Lawyers (AAML)', 'https://www.aaml.org/the-2025-aaml-institute-for-family-law-associates-a-review-and-recommendation-part-1-why-every-associate-should-attend-the-aaml-institute/', NULL, NULL, NULL, 'custody divorce financial news', FALSE),
  (76, 'Virginia''s 2025 Protective Order Expansion: Up to Four-Year Orders Now Available', 'Effective July 1, 2025, Virginia courts may issue protective orders lasting up to four years — double the previous maximum of two years — when the respondent has had a prior protective order within the past 10 years. Military protective orders are now admissible as evidence in civil family court proceedings, and courts are required to notify military authorities when a civil protective order is violated. Persons convicted of rape or incest are expressly barred from obtaining custody or visitation with children conceived through those acts, with civil courts able to apply the restriction based on clear and convincing evidence.', '2025-07-01', 'news', '{"domestic_violence","custody","child_welfare"}', 'Virginia General Assembly', 'https://www.familylawva.com/key-changes-to-virginia-family-law-in-2025-what-you-need-to-know/', NULL, NULL, NULL, 'domestic_violence custody child_welfare news', FALSE),
  (77, 'HB 303 — Divorce Reform: Adultery Grounds Limited to Pre-Separation Conduct; No-Fault Workgroup Mandated', 'HB 303 amends §§ 20-91 and 20-95 of the Code of Virginia to specify that adultery is only a ground for divorce if it occurred prior to the final separation of the parties, closing an ambiguity in current law. The bill also allows a divorce from bed and board to be decreed when parties are living separate and apart—without requiring a waiting period to file—and mandates that the Family Law Coalition, together with the Virginia State Bar Family Law Section, convene a workgroup to develop recommendations for eliminating all fault-based grounds for divorce under Title 20 and transitioning Virginia to an exclusively no-fault system. The workgroup must address impacts on domestic violence survivors, modification of mandatory separation periods, and the continued role of fault in equitable distribution and spousal support; it must report to the Governor and General Assembly by December 1, 2026. The bill passed both chambers (House 64–34 on March 11, 2026) and is awaiting Governor Spanberger''s action by April 13, 2026.', '2026-03-11', 'virginia_code', '{"divorce","adultery","fault-grounds","no-fault","title-20","section-20-91","section-20-95","spousal-support","equitable-distribution","domestic-violence","workgroup"}', 'Virginia LIS — HB 303 (2026 Regular Session)', 'https://lis.virginia.gov/bill-details/20261/HB303', 'HB 303 (2026 Va. Gen. Assembly); amending Va. Code §§ 20-91, 20-95', NULL, NULL, 'divorce adultery fault-grounds no-fault title-20 section-20-91 section-20-95 spousal-support equitable-distribution domestic-violence workgroup virginia_code', FALSE),
  (78, 'HB 93 / SB 38 — Firearm Transfers from Persons Subject to Protective Orders: Age and Residency Restrictions Added', 'HB 93 (identical to SB 38) amends Virginia law governing firearm transfers by persons prohibited from possession due to a protective order or a conviction for assault and battery of a family or household member. Under the new provisions, a transferee must be at least 21 years old and must not reside with the prohibited person—requirements absent under current law. The bill also adds a reporting requirement: the prohibited person must provide the court clerk with the transferee''s name, address, and signature and supply a copy to the transferee. Additionally, law enforcement must advise prohibited persons that a search warrant may be obtained if probable cause exists to search for firearms. The bill was enrolled and communicated to Governor Spanberger on March 10, 2026, with an action deadline of April 13, 2026.', '2026-03-10', 'virginia_code', '{"domestic-violence","protective-orders","firearms","firearm-surrender","title-16-1","custody","family-abuse"}', 'Virginia LIS — HB 93 (2026 Regular Session)', 'https://lis.virginia.gov/bill-details/20261/HB93', 'HB 93 / SB 38 (2026 Va. Gen. Assembly)', NULL, 'Moms Demand Action|https://momsdemandaction.org/press/virginia-makes-history-as-general-assembly-sends-landmark-slate-of-gun-safety-bills-to-governor-spanbergers-desk/', 'domestic-violence protective-orders firearms firearm-surrender title-16-1 custody family-abuse virginia_code', FALSE),
  (79, 'HB 19 / SB 160 — Closes ''Intimate Partner Loophole'': Firearms Prohibited After DV Conviction Against Dating Partner', 'HB 19 (identical to SB 160) closes a longstanding gap in Virginia''s domestic violence firearm laws by expanding the definition of ''family or household member''—as it applies to J&DR courts and firearm prohibitions—to include intimate partners, defined as individuals who were in a romantic, dating, or sexual relationship with the person within the previous 12 months. The bill also extends the prohibition to individuals who cohabited with the person within the past 12 months, and creates a new Class 1 misdemeanor for any person who knowingly purchases, possesses, or transports a firearm after a conviction for assault and battery against an intimate partner (for conduct on or after July 1, 2026). The enrolled bill was communicated to Governor Spanberger on March 14, 2026, and awaits action by April 13, 2026.', '2026-03-14', 'virginia_code', '{"domestic-violence","firearms","intimate-partner","title-16-1","family-household-member","j-dr-court","protective-orders"}', 'Virginia LIS — HB 19 (2026 Regular Session)', 'https://lis.virginia.gov/bill-details/20261/HB19', 'HB 19 / SB 160 (2026 Va. Gen. Assembly)', NULL, 'VPM News|https://www.vpm.org/generalassembly/2026-03-14/sine-die-ga-session-budget-affordability-spanberger-ahmad-farnsworth', 'domestic-violence firearms intimate-partner title-16-1 family-household-member j-dr-court protective-orders virginia_code', FALSE),
  (80, 'HB 301 — Adult Adoptees Gain Right to Access Original Birth Certificate', 'HB 301 requires the Virginia State Registrar to provide adult adoptees with their original birth certificate upon request, subject to submission of an application and proof of identity. The bill includes a contact preference form that birth parents may complete to indicate whether they consent to contact, wish to be contacted only through an intermediary, or prefer no contact—giving birth parents a voice in the process without blocking access. This makes Virginia the first in the South to open sealed adoption birth certificate records to adult adoptees, moving away from its status as a ''closed record'' state. The enrolled bill was communicated to Governor Spanberger on March 14, 2026, awaiting action by April 13, 2026.', '2026-03-14', 'virginia_code', '{"adoption","birth-certificate","adoptee-rights","title-63-2","sealed-records","contact-preference"}', 'Virginia LIS — HB 301 (2026 Regular Session)', 'https://lis.virginia.gov/bill-details/20261/HB301', 'HB 301 (2026 Va. Gen. Assembly)', NULL, 'WSET News|https://wset.com/news/local/it-means-everything-adoption-bill-spurred-by-mark-spain-passes-state-legislature-march-2026', 'adoption birth-certificate adoptee-rights title-63-2 sealed-records contact-preference virginia_code', FALSE),
  (81, 'HB 1207 / SB 2 — Virginia Paid Family and Medical Leave Passes, Includes Parental and Safe Leave for DV Survivors', 'HB 1207 (companion SB 2) establishes a state-administered paid family and medical leave insurance program under the Virginia Employment Commission, making Virginia the first Southern state to enact such a law. The program—funded by employer and employee payroll contributions beginning July 1, 2028, with benefits starting December 1, 2028—provides up to 12 weeks of paid leave per year at 80% of average weekly wages for parental bonding, serious medical conditions, caregiving for a family member, military deployment, and ''safe leave'' for workers or family members experiencing domestic violence, sexual assault, or stalking. The inclusive definition of ''family member'' covers spouses, domestic partners, children, parents, siblings, grandparents, and chosen family. Governor Spanberger, who championed the bill, is expected to sign it; action deadline is April 13, 2026.', '2026-03-13', 'virginia_code', '{"paid-family-leave","parental-leave","domestic-violence","safe-leave","child-welfare","family-law"}', 'Virginia LIS — HB 1207 (2026 Regular Session)', 'https://lis.virginia.gov/bill-details/20261/HB1207', 'HB 1207 / SB 2 (2026 Va. Gen. Assembly)', NULL, 'National Partnership for Women & Families|https://nationalpartnership.org/news_post/npwf-celebrates-virginia-becoming-the-15th-state-and-first-in-the-south-to-pass-paid-family-and-medical-leave/', 'paid-family-leave parental-leave domestic-violence safe-leave child-welfare family-law virginia_code', FALSE),
  (82, 'HB 5 / SB 199 — Virginia Paid Sick and Safe Leave Enacted, Covering Domestic Violence and Stalking Victims', 'HB 5 (companion SB 199) gives Virginia workers the right to earn up to 40 hours of paid sick and safe leave per year, including ''safe leave'' specifically for workers—or their family members—who have experienced domestic violence, sexual assault, or stalking. Leave may be used for medical care, safety planning, court proceedings, relocation, or securing housing related to the abuse. The bill passed both chambers on March 13, 2026, and is awaiting Governor Spanberger''s signature; she is expected to sign. This is the third consecutive year the legislature passed this measure, having previously been vetoed by Governor Youngkin.', '2026-03-13', 'virginia_code', '{"domestic-violence","safe-leave","paid-sick-leave","stalking","sexual-assault","family-law","workplace"}', 'Virginia LIS — HB 5 (2026 Regular Session)', 'https://lis.virginia.gov/bill-details/20261/HB5', 'HB 5 / SB 199 (2026 Va. Gen. Assembly)', NULL, 'National Partnership for Women & Families|https://nationalpartnership.org/news_post/virginia-passage-of-paid-sick-days-and-paid-safe-leave-shows-commitment-to-working-people/', 'domestic-violence safe-leave paid-sick-leave stalking sexual-assault family-law workplace virginia_code', FALSE),
  (83, 'Perkins v. Howington — Supreme Court of Virginia Clarifies "Just Cause" Standard for Adoption Without Birth Parent Consent', 'The Supreme Court of Virginia held that the "just cause" inquiry under Code § 63.2-1202(H)—which permits adoption without birth parent consent when the parent has had no contact with the child for six months before the petition—requires a fact-specific, discretionary analysis rather than a bright-line rule. The Court rejected the Court of Appeals'' per se holding that a no-contact order arising from a parent''s own misconduct can never constitute just cause. Although correcting the lower court''s reasoning, the Court affirmed the adoption, finding that the trial court did not abuse its discretion where the birth mother''s drug use caused the no-contact order, she failed to diligently pursue modification, and her lack of contact was therefore unjustified.', '2026-03-12', 'case_law', '{"adoption","parental rights","consent to adoption","just cause","no-contact order","termination of parental rights","appellate practice"}', 'Virginia Appellate Law Blog (Blankingship & Keith)', 'https://www.blankingshipandkeith.com/news-insights/supreme-court-of-virginia-clarifies-just-cause-standard-for-adoption-without-birth-parent-consent', 'Perkins v. Howington, Record No. 240960 (Va. Mar. 12, 2026)', 'Supreme Court of Virginia', 'Virginia Appellate Law Blog|https://virginiaappeals.org', 'adoption parental rights consent to adoption just cause no-contact order termination of parental rights appellate practice case_law Supreme Court of Virginia', FALSE),
  (84, 'Ashby v. Wythe County Department of Social Services — Court of Appeals Affirms Child Abuse/Neglect Finding and Custody Transfer to Grandmother', 'The Court of Appeals of Virginia affirmed the circuit court''s finding that Benjamin Howard Ashby abused or neglected his minor children M.A. (age 4) and B.A. (age 6 months) under a preponderance of the evidence standard. Evidence of M.A.''s sexualized behaviors—including sounds and movements described by multiple adult witnesses and correlating with father''s visitation periods—was properly admitted and was sufficient to sustain the abuse and neglect finding. The court also upheld the transfer of custody to the maternal grandmother and a protective order restricting the father''s contact.', '2026-03-17', 'case_law', '{"abuse and neglect","child protective services","custody","evidence","admissibility","sexualized behavior","DSS","protective orders","parental rights"}', 'Justia Virginia Court of Appeals', 'https://law.justia.com/cases/virginia/court-of-appeals-unpublished/2026/1179-25-3.html', 'Benjamin Howard Ashby v. Wythe County Department of Social Services, Record No. 1179-25-3 (Va. Ct. App. Mar. 17, 2026) (unpublished)', 'Court of Appeals of Virginia', NULL, 'abuse and neglect child protective services custody evidence admissibility sexualized behavior DSS protective orders parental rights case_law Court of Appeals of Virginia', FALSE),
  (85, '2026 VSB Annual Meeting Registration Opens — Virginia Beach, June 4–6', 'The Virginia State Bar opened registration on March 16, 2026 for its 2026 Annual Meeting, scheduled for June 4–6 in Virginia Beach. This year''s theme is ''Waves of Change: How Virginia Lawyers Make a Difference.'' The event offers 12.5 CLE hours including 4.5 ethics hours (pending), through a combination of live and on-demand programming, with showcase CLE sessions, award ceremonies, and networking.', '2026-03-16', 'va_state_bar', '{"VSB Annual Meeting","CLE","Virginia Beach","2026","ethics CLE"}', 'Virginia State Bar', 'https://vsb.org/Site/news/news-items/20260316-am-registration-open.aspx', NULL, NULL, NULL, 'VSB Annual Meeting CLE Virginia Beach 2026 ethics CLE va_state_bar', FALSE),
  (86, 'Bruce H. Russell II Named VSB 2026–2027 President-Elect', 'On March 16, 2026, the Virginia State Bar announced that Bruce H. Russell II, of Bruce H. Russell II, P.C. in Lebanon, Virginia, will serve as VSB president-elect for 2026–2027, succeeding Susan Bradford Tarley as president on July 1. Russell has practiced law for over 25 years across Southwest Virginia, handling traffic and criminal defense, personal injury, and family law, and has held numerous VSB leadership roles including chair of the Bench-Bar Relations Committee and member of the Executive Committee.', '2026-03-16', 'va_state_bar', '{"VSB leadership","president-elect","Bruce Russell","bar governance"}', 'Virginia State Bar', 'https://vsb.org/Site/news/news-items/20260316-russell-pres-elect.aspx', NULL, NULL, NULL, 'VSB leadership president-elect Bruce Russell bar governance va_state_bar', FALSE),
  (87, 'Public Reprimand With Terms — Standish Alexander (Safekeeping Property)', 'Effective March 17, 2026, the Third District, Section III Subcommittee of the Virginia State Bar issued a public reprimand with terms to Standish Alexander for violating professional rules governing safekeeping property. This disciplinary action was posted on the VSB website on March 18, 2026.', '2026-03-17', 'attorney_discipline', '{"public reprimand","safekeeping property","Rule 1.15","Third District","attorney discipline"}', 'Virginia State Bar — Disciplinary System Actions', 'https://vsb.org/Site/Site/news/disciplinary-actions.aspx', NULL, NULL, NULL, 'public reprimand safekeeping property Rule 1.15 Third District attorney discipline attorney_discipline', FALSE),
  (88, 'Virginia Supreme Court Affirms Two-Year Suspension of Petersburg Prosecutor — Lee v. Virginia State Bar', 'In a unanimous opinion dated March 19, 2026, the Supreme Court of Virginia affirmed the two-year license suspension of Petersburg prosecutor Joseph Willis Lee III for violating Disciplinary Rule 3.8(d) by knowingly withholding exculpatory evidence—specifically, a charge-reduction deal with a key witness—in the 2024 murder trial of Rayshawn Scott, whose conviction was subsequently vacated. The Court, through Justice Arthur Kelsey, held that alleged irregularities in the VSB''s preliminary certification process were harmless after a fair de novo three-judge circuit court trial applying the clear-and-convincing-evidence standard, and rejected Lee''s argument that favorable statements by the criminal trial judge negated disciplinary liability. The decision clarifies that Brady violations do not require intent, and that disciplinary proceedings are not precluded by a criminal court''s characterizations of attorney conduct.', '2026-03-19', 'attorney_discipline', '{"Supreme Court of Virginia","prosecutor discipline","Brady violation","Rule 3.8(d)","discovery violation","exculpatory evidence","Joseph Lee","Petersburg"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2026/03/20/va-supreme-court-upholds-petersburg-prosecutor-license-suspension/', 'Lee v. Virginia State Bar, Va. (Mar. 19, 2026)', 'Supreme Court of Virginia', 'CaseMine Legal Commentary|https://www.casemine.com/commentary/us/lee-v.-virginia-state-bar:-harmless-error-cure-for-alleged-bar-certification-irregularities-after-de-novo-discipline-trial/view', 'Supreme Court of Virginia prosecutor discipline Brady violation Rule 3.8(d) discovery violation exculpatory evidence Joseph Lee Petersburg attorney_discipline Supreme Court of Virginia', FALSE),
  (89, 'VSB Issues Scam Alert: Nationwide Scheme Targeting Lawyers via Fake Clients and Debtors', 'On March 20, 2026, the Virginia State Bar warned attorneys about a nationwide scam in which fraudsters impersonate prospective clients and debtors to defraud law firms, typically by inducing lawyers to receive and wire fraudulent funds. The VSB directed attorneys to a 2022 Virginia Lawyer article by Christopher Parke Benjamin—updated for current conditions—for detailed guidance on how to identify and avoid the phantom-client/phantom-funds scam.', '2026-03-20', 'va_state_bar', '{"scam alert","wire fraud","impersonation","lawyer fraud","cybersecurity","risk management"}', 'Virginia State Bar', 'https://vsb.org/Site/news/news-items/20260320-lawyer-scam.aspx', NULL, NULL, NULL, 'scam alert wire fraud impersonation lawyer fraud cybersecurity risk management va_state_bar', FALSE),
  (90, '60-Day Suspension — Lenard Tyrone Myers Jr. (Effective April 1, 2026)', 'On March 20, 2026, the Virginia State Bar Disciplinary Board posted an order suspending Lenard Tyrone Myers Jr.''s license to practice law in Virginia for 60 days, effective April 1, 2026. The underlying violations were not specified in the public posting.', '2026-03-20', 'attorney_discipline', '{"suspension","attorney discipline","VSB Disciplinary Board","Lenard Myers"}', 'Virginia State Bar — Disciplinary Actions: Suspension', 'https://vsb.org/EN/Site/news/summary-filters/summaries-typefilter-suspension.aspx', NULL, NULL, NULL, 'suspension attorney discipline VSB Disciplinary Board Lenard Myers attorney_discipline', FALSE),
  (91, 'VSB Family Law Section — Brian M. Hirsch Named 2026 Betty A. Thompson Lifetime Achievement Award Recipient', 'On March 20, 2026, the Virginia State Bar announced that Brian M. Hirsch of Hirsch & Ehlenberger in Reston has been named the 2026 recipient of the Betty A. Thompson Lifetime Achievement Award by the VSB''s Family Law Section. The award recognizes a Virginia family law attorney for distinguished lifetime service to the practice area and the profession.', '2026-03-20', 'va_state_bar', '{"family law","VSB Family Law Section","lifetime achievement award","Betty Thompson Award","Brian Hirsch"}', 'Virginia State Bar — News and Resources', 'https://vsb.org/IN/Site/05_News-and-resources/bar-news.aspx', NULL, NULL, NULL, 'family law VSB Family Law Section lifetime achievement award Betty Thompson Award Brian Hirsch va_state_bar', FALSE),
  (92, 'VSB Family Law Section — Julie M. Cillo Receives 2026 Family Law Service Award', 'On March 20, 2026, the Virginia State Bar Family Law Section Board of Governors awarded the 2026 Family Law Service Award to Julie M. Cillo, a partner at Owen & Owens, PLC. The award recognizes significant service and contributions to Virginia''s family law bar.', '2026-03-20', 'va_state_bar', '{"family law","VSB Family Law Section","service award","Julie Cillo","bar award"}', 'Virginia State Bar — News and Resources', 'https://vsb.org/IN/Site/05_News-and-resources/bar-news.aspx', NULL, NULL, NULL, 'family law VSB Family Law Section service award Julie Cillo bar award va_state_bar', FALSE),
  (93, 'VSB Opens Faculty Nominations for Harry L. Carrico Professionalism Course', 'Effective March 20, 2026, the Virginia State Bar opened nominations for new faculty members to teach the mandatory Harry L. Carrico Professionalism Course, which serves as many new lawyers'' first introduction to the VSB''s professionalism standards. Members of the bench and bar may nominate up to three candidates demonstrating excellence and professionalism; faculty serve three-year terms. Nominations are due by April 30, 2026.', '2026-03-20', 'va_state_bar', '{"Harry Carrico Professionalism Course","new lawyer training","professionalism","faculty nominations","mandatory CLE"}', 'Virginia State Bar', 'https://vsb.org/Site/news/news-items/20260320-vsb-professionalism-course-nominations.aspx', NULL, NULL, NULL, 'Harry Carrico Professionalism Course new lawyer training professionalism faculty nominations mandatory CLE va_state_bar', FALSE),
  (94, 'Six-Month Suspension — Marlene Alice Harris of Midlothian (Effective March 21, 2026)', 'Effective March 21, 2026, the Virginia State Bar Disciplinary Board suspended Marlene Alice Harris (PO Box 4279, Midlothian, VA 23112) for six months for violating professional rules governing diligence, communication, and declining or terminating representation. This was an agreed disposition; the matter arose under VSB Docket No. 25-031-134513.', '2026-03-21', 'attorney_discipline', '{"suspension","attorney discipline","VSB Disciplinary Board","diligence","communication","Rule 1.3","Rule 1.4","Rule 1.16","agreed disposition","Midlothian"}', 'Virginia State Bar — Marlene Alice Harris Suspension', 'https://vsb.org/Site/news/summary/20250916-harris.aspx', 'VSB Docket No. 25-031-134513', NULL, NULL, 'suspension attorney discipline VSB Disciplinary Board diligence communication Rule 1.3 Rule 1.4 Rule 1.16 agreed disposition Midlothian attorney_discipline', FALSE),
  (95, 'Virginia General Assembly Passes HB303 Limiting Adultery as Divorce Grounds to Pre-Separation Conduct', 'On March 11, 2026, the Virginia House agreed to Senate amendments on HB303, completing legislative passage by a 64-34 vote. The bill amends Code of Virginia §§ 20-91 and 20-95 to specify that a divorce may be decreed on grounds of adultery only if the adultery occurred prior to the final separation of the parties. Senate amendments also direct a workgroup—including representatives from the Virginia Poverty Law Center and domestic violence organizations—to study transitioning Virginia to an exclusively no-fault divorce system, with a report due December 1, 2026. The bill now awaits gubernatorial action.', '2026-03-11', 'news', '{"virginia","divorce","adultery","no-fault","legislation","HB303"}', 'Virginia Legislative Information System', 'https://lis.virginia.gov/bill-details/20261/HB303', NULL, NULL, NULL, 'virginia divorce adultery no-fault legislation HB303 news', FALSE),
  (96, 'Virginia HB1490 Establishes Centralized Statewide Intake for Child Protective Services Reports', 'Approved by the Virginia General Assembly in the final days of its 2026 regular session, HB1490 (Tran) and companion SB640 (Pillion) overhaul how child abuse and neglect reports are received by creating a 24/7 centralized hotline operated by the Virginia Department of Social Services (VDSS). Under the current system, validity determinations are handled by local departments; the new law shifts that authority to VDSS, which will then refer valid complaints to local departments for investigation. Implementation is phased beginning July 1, 2028 through July 1, 2030, and a stakeholder workgroup report on best practices is due December 1, 2026. The legislation also expands the rapid-response requirement for reports involving children under age three (from under-two to under-three).', '2026-03-17', 'news', '{"virginia","child welfare","child abuse","child protective services","legislation","HB1490"}', 'Virginia Association of Counties', 'https://www.vaco.org/capitol-contact/legislation-centralizing-intake-for-child-protective-services-providing-state-oversight-of-local-departments-of-social-services-approved-by-general-assembly/', NULL, NULL, NULL, 'virginia child welfare child abuse child protective services legislation HB1490 news', FALSE),
  (97, 'DC Council Holds Public Hearing on Child Support Improvement Amendment Act of 2026', 'On March 18, 2026, the DC Council Committee on the Judiciary and Public Safety held a public hearing on Bill 26-0572, the Child Support Improvement Amendment Act of 2026. DC Attorney General Brian Schwalb testified in support, and Legal Aid DC submitted extensive testimony. The bill would enact a phased full pass-through of all child support payments to families currently or formerly receiving TANF—ensuring 100% of payments reach children rather than being split between the District and federal government—and would restructure the period of enforceability for child support arrears. Advocates also urged additions including automatic suspension of child support obligations during incarceration, exemption of low-income parents from driver''s license suspension, and cancellation of arrears beyond the statute of limitations.', '2026-03-18', 'news', '{"child support","DC","legislation","TANF","poverty","racial equity","reform"}', 'DC Office of the Attorney General', 'https://oag.dc.gov/release/attorney-general-schwalb-testifies-support-child', NULL, NULL, 'Legal Aid DC|https://www.legalaiddc.org/sites/default/files/2026-03/Child%20Support%20Improvement%20Act%202026%20Testimony%20-%20Master%20Draft%20-%2003.18.2026%20-%20FINAL.pdf', 'child support DC legislation TANF poverty racial equity reform news', FALSE),
  (98, 'Children''s Bureau Removes ''Cultural Competence'' Language from Child Welfare Policy Manual', 'Reported the week of March 20, 2026, the Children''s Bureau amended Section 8.1H, Question 21 of the Child Welfare Policy Manual (Title IV-E, Administrative Functions/Costs, Training) to remove ''cultural competence'' and related language from the list of allowable Title IV-E training topics. The revision affects what states may claim as federally reimbursable training costs in child welfare programs. This change follows the Trump administration''s broader deregulatory agenda, including the February 2026 rescission of approximately 35,781 pages of sub-regulatory guidance issued by the Administration for Children and Families.', '2026-03-20', 'news', '{"federal","child welfare","Children's Bureau","Title IV-E","training","policy change","Trump administration"}', 'Social Current', 'https://www.social-current.org/2026/03/mar-23-federal-update-childrens-bureau-revises-child-welfare-policy-manual/', NULL, NULL, NULL, 'federal child welfare Children''s Bureau Title IV-E training policy change Trump administration news', FALSE),
  (99, 'Trump Administration Proposes Rescission of Biden-Era LGBTQ+ Foster Care Placement Rule', 'On March 6, 2026, the Administration for Children and Families (ACF) published a proposed rule in the Federal Register to formally rescind a 2024 Biden-era regulation that required states to maintain a supply of ''designated placements'' affirming of LGBTQ+ youth in foster care—providers specifically trained on LGBTQ+ needs and offering access to affirming mental health services. The original rule had already been halted nationwide by a federal district court in Texas in summer 2025. The proposed rescission, published at 91 FR 11017, would remove the 15% designated placement expectation and related foster care provider requirements under Titles IV-E and IV-B. LGBTQ+ advocacy groups including Lambda Legal criticized the rollback as harmful to one of foster care''s most vulnerable populations.', '2026-03-06', 'news', '{"federal","LGBTQ+","foster care","child welfare","ACF","Trump administration","policy change"}', 'The Imprint', 'https://imprintnews.org/youth-services-insider/acf-rescinding-biden-era-rule-lgbtq-foster-care/271775', '91 FR 11017 (Mar. 6, 2026)', NULL, NULL, 'federal LGBTQ+ foster care child welfare ACF Trump administration policy change news', FALSE),
  (100, 'England and Wales to Roll Out ''Child-Focused Courts'' Nationwide Following Successful Pilot', 'On March 19, 2026, UK Justice Secretary David Lammy announced the national expansion of a ''child-focused courts'' model—previously piloted as ''pathfinder courts''—across all of England and Wales. The model assigns a family court advisor or social worker to meet with children before hearings to produce a ''child impact report'' that flags safeguarding risks including domestic abuse, and supports parents in reaching agreement without litigation where safe. Trials showed court backlogs halved and cases resolved up to seven months faster. The rollout will add 13 new court areas in the next financial year, with full national implementation in subsequent years, backed by £17 million in government funding. The president of the family division, Sir Andrew McFarlane, called it ''truly groundbreaking'' and a ''game changer'' for families.', '2026-03-19', 'news', '{"international","England","Wales","child-focused courts","family court reform","domestic abuse","custody","court reform"}', 'The Bureau of Investigative Journalism', 'https://www.thebureauinvestigates.com/stories/2026-03-19/groundbreaking-new-family-court-model-will-put-childs-needs-first', NULL, NULL, NULL, 'international England Wales child-focused courts family court reform domestic abuse custody court reform news', FALSE),
  (101, 'New Jersey Kayden''s Law Custody Reforms Draw Continued Practitioner Analysis in March 2026', 'New Jersey''s sweeping child custody statute reforms—signed by Governor Phil Murphy on January 20, 2026 as S4510/A5761 (Kayden''s Law)—continued to generate significant practitioner analysis and client guidance in March 2026. The law amends N.J.S.A. 9:2-4 to make child safety the threshold inquiry in custody cases, replacing the prior presumption of frequent contact with both parents; adds 15 non-exhaustive best-interest factors; bars courts from presuming parental alienation without investigating the child''s actual reasons for resistance; requires judges to make detailed on-the-record findings when custody departs from a child''s stated preference; essentially eliminates court-ordered reunification therapy; and mandates specialized training for mental health professionals in abuse cases. Lyons & Associates published detailed practitioner guidance on March 13, 2026, noting the law applies immediately to all pending and future cases.', '2026-03-13', 'news', '{"New Jersey","custody","Kayden's Law","child safety","domestic violence","parental alienation","reunification therapy","legislation"}', 'Lyons & Associates, P.C.', 'https://www.lyonspc.com/2026/03/13/what-parents-need-to-know-about-the-sweeping-and-significant-changes-to-the-new-jersey-custody-statute/', 'N.J.S.A. 9:2-4 as amended by S4510/A5761 (Jan. 20, 2026)', NULL, 'Lyons & Associates, P.C.|https://www.lyonspc.com/2026/03/13/what-parents-need-to-know-about-the-sweeping-and-significant-changes-to-the-new-jersey-custody-statute/', 'New Jersey custody Kayden''s Law child safety domestic violence parental alienation reunification therapy legislation news', FALSE),
  (102, 'AI Bias in Custody Evaluation Tools Emerges as Practitioner Concern in Family Courts', 'A March 2026 analysis by Steele Family Law highlights the growing use of AI-powered risk assessment and custody evaluation tools in family courts—particularly in Illinois—and the significant risks of algorithmic bias embedded in historical training data. The analysis identifies key vulnerabilities: training data contamination reflecting decades of socioeconomic and gender bias, opaque ''black box'' decision-making that evaluators cannot fully explain on cross-examination, failure to account for parenting context, and susceptibility to manipulated inputs. Strategic recommendations for attorneys include demanding disclosure of AI tools and training methodologies, retaining data scientists as experts, auditing clients'' digital ecosystems before evaluation, and building human-context records that algorithms cannot capture.', '2026-03-07', 'trends', '{"AI","artificial intelligence","custody evaluation","bias","technology","family court","Illinois","digital evidence"}', 'Steele Family Law', 'https://steelefamlaw.com/article/ai-bias-in-family-court-recommendations', NULL, NULL, 'Steele Family Law|https://steelefamlaw.com/article/ai-bias-in-family-court-recommendations', 'AI artificial intelligence custody evaluation bias technology family court Illinois digital evidence trends', FALSE),
  (103, 'Rise of Mediation and Collaborative Divorce Accelerates in 2026 as Courts Embrace Alternative Dispute Resolution', 'Multiple analyses published in March 2026 document an accelerating shift toward mediation and collaborative divorce as the preferred approach for families navigating separation. Factors driving the trend include rising litigation costs and court backlogs, mental health research documenting psychological harm of prolonged adversarial proceedings to children, improved virtual mediation access, and court integration of mediation into case management—particularly for custody matters. A March 18, 2026 piece by the Florida Collaborative Law Center Group notes faster resolutions, lower legal expenses, and more durable agreements as key advantages. A Missouri-focused analysis by Haefner Law Office observes that many courts now require mediation attempts before contested custody hearings. The cultural shift away from ''winner-take-all'' divorce and toward collaborative, privacy-focused settlements is documented as one of 2026''s defining family law trends.', '2026-03-18', 'trends', '{"mediation","collaborative divorce","alternative dispute resolution","family law practice","trends","court reform"}', 'Florida Collaborative Law Center Group', 'https://fclcgroup.com/the-rise-of-mediation-and-collaborative-divorce-in-2026/', NULL, NULL, NULL, 'mediation collaborative divorce alternative dispute resolution family law practice trends court reform trends', FALSE),
  (112, 'HB 942 (Cannabis/Custody): Awaiting Governor Spanberger Action — April 13 Deadline', 'HB 942, patroned by Del. Nadarius Clark (D), passed both chambers of the Virginia General Assembly and was enrolled and communicated to Gov. Abigail Spanberger on March 14, 2026. The bill amends the Code of Virginia to provide that a person''s legal possession or consumption of authorized substances (including cannabis) alone shall not serve as a basis to restrict custody or visitation, unless other facts establish that the possession or consumption creates a risk of physical or mental injury to the child or is clearly not in the child''s best interest. It also prevents courts from construing a positive drug test for legally authorized substances as a failed test in custody proceedings. The governor has until 11:59 p.m. on April 13, 2026 to sign, veto, or return the bill with amendments. A similar bill was vetoed by former Gov. Glenn Youngkin; Gov. Spanberger is expected to sign it given her administration''s more receptive posture on cannabis reform.', '2026-03-14', 'virginia_code', '{"HB 942","cannabis","custody","visitation","authorized substances","drug testing","Spanberger","awaiting governor action"}', 'Virginia LIS — HB942', 'https://lis.virginia.gov/bill-details/20261/HB942', '2026 Va. HB 942 (proposed amend. to Va. Code §§ 20-124.2, 20-124.3, 16.1-278.15)', NULL, 'Marijuana Moment|https://www.marijuanamoment.net/virginia-bill-to-protect-rights-of-parents-who-use-marijuana-heads-to-governors-desk/', 'HB 942 cannabis custody visitation authorized substances drug testing Spanberger awaiting governor action virginia_code', FALSE),
  (113, 'HB 303 (Fault Divorce Reform): Passed with Senate Workgroup Amendment — Awaiting Governor Action', 'HB 303, Virginia''s fault divorce reform bill, passed both chambers on March 11, 2026, with a significant Senate amendment that narrowed its scope. As originally introduced, the bill would have allowed adultery-based fault divorce only when the adultery occurred before the parties'' final separation (closing the ''post-separation adultery'' loophole) and permitted immediate filing for a divorce from bed and board on separation grounds. The Senate added an amendment creating a formal workgroup — comprising the Family Law Coalition, VSB Family Law Section, Virginia Poverty Law Center, domestic violence organizations, circuit judiciary, VDSS, law school faculty, and legislative members — to study transitioning Virginia to an exclusively no-fault divorce system, including modifying separation periods, addressing fault''s role in equitable distribution and spousal support, and protecting domestic violence survivors, with a report due to the Governor and Courts of Justice committee chairs by December 1, 2026. The bill is enrolled and awaiting Gov. Spanberger''s action before the April 13, 2026 deadline.', '2026-03-11', 'virginia_code', '{"HB 303","fault divorce","no-fault divorce","adultery","separation","divorce reform","workgroup","awaiting governor action"}', 'Virginia LIS — HB303', 'https://lis.virginia.gov/bill-details/20261/HB303', '2026 Va. HB 303 (proposed amend. to Va. Code §§ 20-91, 20-95)', NULL, NULL, 'HB 303 fault divorce no-fault divorce adultery separation divorce reform workgroup awaiting governor action virginia_code', FALSE),
  (114, 'HB 93 / SB 38 (Protective Order Firearm Transfers): Enrolled, Awaiting Governor — April 13 Deadline', 'HB 93 (identical to SB 38), patroned by Del. Bennett-Parker and Sen. Favola, passed the House 62-35 and the Senate 21-19, was enrolled on March 4, 2026, and communicated to Gov. Spanberger on March 10, 2026. The bill tightens rules for firearm transfers by persons subject to protective orders or convicted of assault and battery of a family or household member: it requires that any transferee (not otherwise prohibited) be at least 21 years of age and not reside with the prohibited person. It also creates a mandatory notification requirement — the prohibited person must inform the clerk of court of the transferee''s name, address, and signature, and provide the transferee a copy. The bill further requires that prohibited persons be advised that law enforcement may seek a search warrant for firearms if probable cause exists. This legislation directly addresses domestic violence survivor protection. Gov. Spanberger has until April 13, 2026 to act.', '2026-03-10', 'virginia_code', '{"HB 93","SB 38","protective order","firearms","domestic violence","firearm transfer","family abuse","awaiting governor action"}', 'Virginia LIS — HB93', 'https://lis.virginia.gov/bill-details/20261/HB93', '2026 Va. HB 93 / SB 38 (proposed amend. to Va. Code § 18.2-308.09 et seq.)', NULL, 'Everytown for Gun Safety|https://www.everytown.org/press/virginia-makes-history-as-general-assembly-sends-landmark-slate-of-gun-safety-bills-to-governor-spanbergers-desk/', 'HB 93 SB 38 protective order firearms domestic violence firearm transfer family abuse awaiting governor action virginia_code', FALSE),
  (115, 'HB 19 / SB 160 (Intimate Partner Loophole): Enrolled, Awaiting Governor — Closes Misdemeanor DV Firearm Gap', 'HB 19 (patroned by Del. McClure) and SB 160 (Sen. Perry) close the so-called ''Intimate Partner Loophole'' by strengthening prohibitions on firearm possession and purchase for persons convicted of misdemeanor domestic violence crimes against intimate partners (dating partners and others outside the traditional ''family or household member'' definition). Both bills were enrolled and communicated to Gov. Spanberger on March 14, 2026, with the governor''s action deadline of April 13, 2026. A fiscal impact statement was filed on March 18, 2026. The bills address a longstanding gap in Virginia law where individuals convicted of misdemeanor domestic assault against a dating partner, rather than a family or household member, could legally continue to possess firearms. The legislation aligns Virginia law more closely with federal domestic violence firearms prohibitions.', '2026-03-14', 'virginia_code', '{"HB 19","SB 160","intimate partner loophole","domestic violence","firearms","misdemeanor assault","dating violence","awaiting governor action"}', 'Virginia LIS — HB19', 'https://lis.virginia.gov/bill-details/20261/HB19', '2026 Va. HB 19 / SB 160 (proposed amend. to Va. Code § 18.2-308.1:8)', NULL, 'Everytown for Gun Safety|https://www.everytown.org/press/virginia-makes-history-as-general-assembly-sends-landmark-slate-of-gun-safety-bills-to-governor-spanbergers-desk/', 'HB 19 SB 160 intimate partner loophole domestic violence firearms misdemeanor assault dating violence awaiting governor action virginia_code', FALSE),
  (116, 'HB 301 (Adoptee Birth Certificates): Enrolled, Awaiting Governor — Opens Access for Adult Adoptees', 'HB 301 (patroned by Del. Katrina Callsen, co-championed with Del. Wendell Walker after four years of advocacy) passed the General Assembly with bipartisan support and was enrolled and communicated to Gov. Spanberger on March 14, 2026, with the April 13 deadline. The bill gives adult adoptees in Virginia a straightforward path to obtain their original birth certificate — currently sealed under Virginia''s status as a ''closed adoption state.'' The legislation also provides birth parents the opportunity to express their contact preferences. Virginia has been one of approximately 15 states with sealed adoption files. The bill was spurred in part by the story of Mark Spain, a real estate executive who spent decades unable to access his original birth records before passing away before the legislation reached the finish line. His story was highlighted in a widely covered WSET report in March 2026.', '2026-03-14', 'virginia_code', '{"HB 301","adoptee","birth certificate","adoption","sealed records","adult adoptee","open records","awaiting governor action"}', 'Virginia LIS — HB301', 'https://lis.virginia.gov/bill-details/20261/HB301', '2026 Va. HB 301 (proposed amend. to Va. Code § 63.2-1247)', NULL, 'WSET — ''It means everything'': Adoption bill spurred by Mark Spain passes state legislature|https://wset.com/news/local/it-means-everything-adoption-bill-spurred-by-mark-spain-passes-state-legislature-march-2026', 'HB 301 adoptee birth certificate adoption sealed records adult adoptee open records awaiting governor action virginia_code', FALSE),
  (117, 'HB 1207 / SB 2 (Paid Family and Medical Leave): Passed Both Chambers, Awaiting Spanberger Signature', 'HB 1207 and SB 2 — Virginia''s paid family and medical leave bills — both passed their respective chambers and are awaiting Gov. Spanberger''s signature, which is widely expected before the April 13, 2026 deadline. The bills establish a payroll-funded insurance program administered by the Virginia Employment Commission, providing eligible workers up to 12 weeks of paid leave at 80% of their average weekly wage (capped at 100% of the statewide average weekly wage). Leave is job-protected and may be taken intermittently. Contributions are split between employers and employees, with employers over 10 employees permitted to pass up to 50% of contributions to employees; employers with 10 or fewer pay a reduced rate with no additional employer contribution. Contributions begin April 1, 2028, with benefit payouts beginning December 1, 2028. The program runs concurrently with FMLA, cannot be waived by agreement (including collective bargaining agreements), and includes an opt-out for commission-approved private plans. This is a landmark change for Virginia employers and working parents.', '2026-03-25', 'virginia_code', '{"HB 1207","SB 2","paid family leave","PFML","parental leave","working parents","Virginia Employment Commission","awaiting governor action"}', 'National Law Review — Virginia Poised to Expand Provisions for Paid Sick Leave and Paid Family Medical Leave', 'https://natlawreview.com/article/virginia-poised-expand-provisions-paid-sick-leave-and-paid-family-medical-leave', '2026 Va. HB 1207 / SB 2', NULL, 'Ogletree Deakins|https://ogletree.com/insights-resources/blog-posts/virginia-poised-to-expand-provisions-for-paid-sick-leave-and-paid-family-medical-leave/', 'HB 1207 SB 2 paid family leave PFML parental leave working parents Virginia Employment Commission awaiting governor action virginia_code', FALSE),
  (118, 'HB 5 / SB 199 (Paid Sick Leave): Passed Both Chambers, Awaiting Spanberger Signature — July 2027 Effective', 'HB 5 and SB 199, Virginia''s universal paid sick leave bills, passed both chambers and are before Gov. Spanberger, who is expected to sign before the April 13, 2026 deadline. The bills expand Virginia''s narrow existing paid sick leave law (currently limited to home health workers) to all public and private employees regardless of employer size, accruing at one hour per 30 hours worked up to 40 hours per year with carryover. Notably, the law explicitly authorizes leave for victims of domestic violence, sexual assault, or stalking to relocate, seek medical care, obtain legal assistance, or use victim services — without requiring disclosure of sensitive health or abuse details as a condition of leave. Enforcement includes a private right of action with double damages for uncompensated leave, and fines up to $500 per violation from the Commissioner of Labor and Industry. If signed, the law takes effect July 1, 2027. The United Steelworkers union filed a rapid-response action call on March 23, 2026 urging members to contact Gov. Spanberger to support the bill.', '2026-03-23', 'virginia_code', '{"HB 5","SB 199","paid sick leave","domestic violence leave","sexual assault leave","stalking leave","employer mandate","awaiting governor action"}', 'United Steelworkers — Urge Your Governor to Strengthen Paid Sick Leave in HB 5/SB 199', 'https://usw.org/news/rapid-response-action-call-virginia-steelworkers-urge-your-governor-to-strengthen-paid-sick-leave-in-hb-5-sb-199/', '2026 Va. HB 5 / SB 199', NULL, 'Ogletree Deakins|https://ogletree.com/insights-resources/blog-posts/virginia-poised-to-expand-provisions-for-paid-sick-leave-and-paid-family-medical-leave/', 'HB 5 SB 199 paid sick leave domestic violence leave sexual assault leave stalking leave employer mandate awaiting governor action virginia_code', FALSE),
  (119, 'Governor Spanberger: All 2026 Family Law Bills Pending — April 13 Deadline', 'As of March 26, 2026, Gov. Abigail Spanberger has not yet signed or vetoed any of the major family law bills passed by the 2026 General Assembly session. The governor has until 11:59 p.m. on April 13, 2026 to act on all enrolled legislation. If she takes no action, bills automatically become law. The General Assembly will reconvene on April 22 to consider any gubernatorial amendments. Key family law bills awaiting action include HB 942 (cannabis/custody), HB 303 (fault divorce reform/workgroup), HB 93/SB 38 (protective order firearm transfers), HB 19/SB 160 (intimate partner loophole), HB 301 (adoptee birth certificates), HB 1207/SB 2 (paid family leave), and HB 5/SB 199 (paid sick leave). Gov. Spanberger stated on March 14 that she was ''reviewing the legislation on my desk as we continue to focus on lowering costs for families.'' She is expected to sign the majority of these bills given her campaign positions and party alignment.', '2026-03-14', 'virginia_code', '{"Governor Spanberger","governor action","April 13 deadline","pending legislation","2026 session","enrolled bills"}', 'Governor of Virginia — Statement on Sine Die Adjournment', 'https://www.governor.virginia.gov/newsroom/news-releases/2026/march-releases/name-1114561-en.html', NULL, NULL, NULL, 'Governor Spanberger governor action April 13 deadline pending legislation 2026 session enrolled bills virginia_code', FALSE),
  (120, 'Childress v. Childress — VA Court of Appeals Affirms Sole Custody, Psychiatric Evaluation Conditions, Social Media Ban (March 24, 2026)', 'In this unpublished Virginia Court of Appeals opinion issued March 24, 2026, the court affirmed a circuit court order awarding sole legal and physical custody of three children to the father following a 7-day trial. The mother — who had been diagnosed with a personality disorder and exhibited symptoms of bipolar disorder, PTSD, and ADHD — had all contact with the children suspended pending completion of a court-approved psychiatric evaluation, diagnosis, and treatment program. The Court of Appeals upheld the psychiatric conditions as a valid exercise of the circuit court''s authority under Va. Code §§ 20-124.2 and 20-124.3, emphasizing that courts may impose conditions protecting children''s welfare when parental mental health directly impacts them, citing Joynes v. Payne and Farley v. Farley. The court also upheld a social media ban restricting both parents from posting about the case, finding it narrowly tailored under Reed v. Town of Gilbert and Packingham v. North Carolina to protect the children and the judicial process. The ruling reaffirms that ongoing psychiatric conditions in custody orders are not a de facto termination of parental rights so long as a clear reunification path exists.', '2026-03-24', 'case_law', '{"custody","mental health","psychiatric evaluation","social media ban","sole custody","visitation restriction","parental fitness","Court of Appeals"}', 'Justia — Childress v. Childress, No. 1843-23-3 (Va. Ct. App. March 24, 2026)', 'https://law.justia.com/cases/virginia/court-of-appeals-unpublished/2026/1843-23-3.html', 'Childress v. Childress, No. 1843-23-3 (Va. Ct. App. Mar. 24, 2026) (unpublished)', 'Court of Appeals of Virginia', NULL, 'custody mental health psychiatric evaluation social media ban sole custody visitation restriction parental fitness Court of Appeals case_law Court of Appeals of Virginia', FALSE),
  (121, 'SCOTUS: No Family Law Opinions Issued March 22–26, 2026 — Criminal and Administrative Decisions Only', 'During the week of March 22–26, 2026, the U.S. Supreme Court issued three opinions: Rico v. United States (No. 24-1056, Mar. 25), Cox Communications, Inc. v. Sony Music Entertainment (No. 24-171, Mar. 25), and Zorn v. Linton (No. 25-297, Mar. 23). None of these decisions directly address family law, parental rights, custody, or domestic relations. The Zorn v. Linton per curiam on March 23 involved a summary reversal on qualified immunity in an excessive force case. The Court also heard oral argument in Watson v. Republican National Committee (election law) on March 23 and Keathley v. Buddy Ayers Construction (bankruptcy) on March 24. The landmark parental rights ruling of the term — Mirabelli v. Bonta, the California school gender transition disclosure case — was issued on March 2, 2026, outside this week''s window. Attorneys should note the upcoming argument in Trump v. Barbara (birthright citizenship) on April 1, 2026.', '2026-03-25', 'scotus', '{"SCOTUS","no opinion","parental rights","Mirabelli v. Bonta","March 2026"}', 'Supreme Court of the United States — Slip Opinions, October Term 2025', 'https://www.supremecourt.gov/opinions/slipopinion/25', NULL, 'Supreme Court of the United States', NULL, 'SCOTUS no opinion parental rights Mirabelli v. Bonta March 2026 scotus Supreme Court of the United States', FALSE),
  (122, 'VSB Legal Ethics Committee Seeks Public Comment on NDAs in Sexual Abuse Settlement Agreements (March 23, 2026)', 'On March 23, 2026, the Virginia State Bar Legal Ethics Committee issued a formal call for public comment on the use of nondisclosure and confidentiality provisions in settlement agreements resolving civil personal injury claims arising from criminal sexual assault, commercial sex trafficking, or other sexual offenses that occurred during the infancy or incapacity of the victim. The inquiry was directed by the General Assembly''s Senate Courts of Justice Committee, which tasked the VSB with studying the issue and making recommendations by November 1, 2026. The committee is seeking input on both policy considerations and legal ethics dimensions — including whether such NDAs create professional responsibility concerns for attorneys who draft or enforce them. Written comments may be submitted to executive director Cameron M. Rountree at publiccomment@vsb.org by close of business on May 15, 2026. This inquiry is particularly relevant to family law practitioners who represent survivors of domestic violence or childhood sexual abuse in civil settlement contexts.', '2026-03-23', 'ethics_opinions', '{"VSB","nondisclosure","NDA","confidentiality","sexual abuse","trafficking","settlement agreement","legal ethics","public comment"}', 'Virginia State Bar — VSB Seeks Comment on Nondisclosure or Confidentiality Provisions', 'https://vsb.org/Site/Site/news/news-items/20260323-vsb-comment-nondisclosure.aspx', NULL, NULL, NULL, 'VSB nondisclosure NDA confidentiality sexual abuse trafficking settlement agreement legal ethics public comment ethics_opinions', FALSE),
  (123, 'VSB Council Approved Proposed Amendments to RPC 1.9 (Conflict of Interest — Former Clients): Petition Pending with Supreme Court of Virginia', 'On February 28, 2026, the VSB Council approved proposed amendments to Rule of Professional Conduct 1.9(c)(1) by a 46-17-1 vote, and the VSB submitted a petition to the Supreme Court of Virginia on March 9, 2026 seeking approval of the rule change. The proposed amendment adds a new exception to the prohibition on using information gained in representing a former client to that client''s disadvantage: a lawyer may use such information when it ''consists solely of criminal history information that can be obtained from law enforcement databases or court records.'' This exception is specifically designed to reduce conflict-of-interest bars that prevent criminal defense lawyers — particularly public defenders in high-volume offices — from representing new clients adverse to former clients, when the only conflict stems from knowledge of a former client''s public criminal record. The exception is particularly relevant in Virginia, where a new criminal record sealing regime takes effect July 1, 2026, which separately allows use of sealed records for exculpatory, mitigating, or impeachment purposes. The Supreme Court of Virginia has not yet ruled on the petition as of March 26, 2026.', '2026-03-09', 'court_rules', '{"RPC 1.9","conflict of interest","former clients","criminal history","public defenders","rule change","Supreme Court of Virginia","VSB"}', 'Virginia State Bar — Amendments to Rule of Professional Conduct 1.9', 'https://vsb.org/Site/Site/news/rules-news/20250327-rule-1.9-conflict-interest.aspx', 'Proposed Amendment to Va. Rules of Prof''l Conduct 1.9(c)(1) (VSB Petition to S. Ct. Va., Mar. 9, 2026)', 'Supreme Court of Virginia', NULL, 'RPC 1.9 conflict of interest former clients criminal history public defenders rule change Supreme Court of Virginia VSB court_rules Supreme Court of Virginia', FALSE),
  (124, 'VSB Discipline: John Paul Forest II Administratively Suspended March 24, 2026 (Subpoena Non-Compliance)', 'On March 24, 2026, the Virginia State Bar Disciplinary Board administratively suspended the law license of John Paul Forest, II for failing to comply with a subpoena duces tecum issued by the Bar. This is an administrative suspension (as opposed to a disciplinary suspension following a full hearing), which typically results from a lawyer''s failure to respond to Bar process. Administrative suspensions become effective immediately upon issuance and remain in place until the attorney complies with the triggering obligation. The VSB posted this action on March 24, 2026. No further details regarding Forest''s practice area or the underlying investigation were publicly disclosed.', '2026-03-24', 'attorney_discipline', '{"VSB","administrative suspension","subpoena","Forest","attorney discipline","March 2026"}', 'Virginia State Bar — Disciplinary System Actions', 'https://vsb.org/Site/Site/news/disciplinary-actions.aspx', NULL, NULL, NULL, 'VSB administrative suspension subpoena Forest attorney discipline March 2026 attorney_discipline', FALSE),
  (125, 'VSB Discipline: Edgar Hampton DeHart Jr. Public Reprimand Without Terms (March 23, 2026)', 'Effective March 23, 2026, the Tenth District, Section I Subcommittee of the Virginia State Bar issued a public reprimand without terms to Edgar Hampton DeHart, Jr. The VSB posted this action on March 24, 2026. No specific professional rule violation was identified in the public summary. A public reprimand without terms is the mildest formal public discipline the VSB can impose, and does not impose any additional conditions or requirements on the attorney beyond the public record of the reprimand itself.', '2026-03-23', 'attorney_discipline', '{"VSB","public reprimand","DeHart","Tenth District","attorney discipline","March 2026"}', 'Virginia State Bar — Disciplinary System Actions', 'https://vsb.org/Site/Site/news/disciplinary-actions.aspx', NULL, NULL, NULL, 'VSB public reprimand DeHart Tenth District attorney discipline March 2026 attorney_discipline', FALSE),
  (126, 'VSB Discipline: Udoka Uzoamaka Angela Obi Public Reprimand With Terms (Effective March 18, 2026)', 'Effective March 18, 2026, the First District Subcommittee of the Virginia State Bar issued a public reprimand with terms to Udoka Uzoamaka Angela Obi. The VSB posted this action on March 24, 2026. No specific professional rule violation was identified in the public summary. A public reprimand with terms differs from one without terms in that the attorney must comply with specific conditions (typically including remedial training, supervision, or other corrective measures) as part of the disposition; failure to comply can result in additional discipline.', '2026-03-18', 'attorney_discipline', '{"VSB","public reprimand","Obi","First District","attorney discipline","March 2026"}', 'Virginia State Bar — Disciplinary System Actions', 'https://vsb.org/Site/Site/news/disciplinary-actions.aspx', NULL, NULL, NULL, 'VSB public reprimand Obi First District attorney discipline March 2026 attorney_discipline', FALSE),
  (127, 'VSB Discipline: Standish Alexander Public Reprimand With Terms for Safekeeping Property Violation (Effective March 17, 2026)', 'Effective March 17, 2026, the Third District, Section III Subcommittee of the Virginia State Bar issued a public reprimand with terms to Standish Alexander for violating professional rules that govern the safekeeping of client property. The VSB posted this action on March 18, 2026. Violations of Va. RPC 1.15 (safekeeping property) typically involve improper handling of client funds or trust accounts, such as commingling funds, failing to maintain adequate records, or disbursing funds without proper authorization. This reprimand with terms requires Alexander to comply with specific conditions as part of the agreed or imposed disposition.', '2026-03-17', 'attorney_discipline', '{"VSB","public reprimand","safekeeping property","trust account","Alexander","Third District","RPC 1.15"}', 'Virginia State Bar — Disciplinary System Actions', 'https://vsb.org/Site/Site/news/disciplinary-actions.aspx', 'Va. RPC 1.15 (Safekeeping Property)', NULL, NULL, 'VSB public reprimand safekeeping property trust account Alexander Third District RPC 1.15 attorney_discipline', FALSE),
  (128, 'Virginia General Assembly Session Ends March 14: Overview of Family Law Bills on Governor''s Desk', 'The 2026 Virginia General Assembly session ended sine die on March 14, 2026, sending more than 1,200 bills to Gov. Abigail Spanberger''s desk. The session was notable for passage of sweeping family-adjacent legislation including paid family and medical leave (HB 1207/SB 2), universal paid sick leave with domestic violence provisions (HB 5/SB 199), a cannabis custody protection bill (HB 942), adoptee birth certificate access (HB 301), fault divorce reform with a no-fault study workgroup (HB 303), two domestic violence firearms bills (HB 93/SB 38 and HB 19/SB 160), and a recreational cannabis retail market set to launch January 1, 2027. The session concluded without a budget agreement, requiring a special session on April 23 for budget purposes, and the General Assembly will reconvene April 22 to consider gubernatorial actions on bills. Spanberger has stated she is reviewing legislation ''as we continue to focus on lowering costs for families.'' The Washington Blade reported on March 24, 2026 that voters will consider a constitutional amendment repealing Virginia''s definition of marriage as between a man and a woman — with the underlying resolution already signed by Spanberger on February 6.', '2026-03-24', 'news', '{"Virginia General Assembly","2026 session","sine die","Spanberger","family law legislation","overview"}', 'Washington Blade — Virginia General Assembly''s 2026 Legislative Session Ends', 'https://www.washingtonblade.com/2026/03/24/virginia-general-assemblys-2026-legislative-session-ends/', NULL, NULL, NULL, 'Virginia General Assembly 2026 session sine die Spanberger family law legislation overview news', FALSE),
  (129, 'Virginia Paid Family and Medical Leave — WSET Report on Employer and Worker Impact (March 25, 2026)', 'WSET (ABC 13 Lynchburg) reported on March 25, 2026 on the pending Virginia paid family and medical leave legislation (HB 1207/SB 2) awaiting Gov. Spanberger''s action. The report highlighted the program''s key features: most employers with more than 10 employees would be required to participate in a state-managed program, eligible workers could take up to 12 weeks at up to 80% of pay with job protection, and the program is designed for family or medical emergencies. Business groups have raised concerns about compliance costs and administrative burden while worker advocates emphasize it would allow parents to bond with a new child, care for seriously ill family members, or recover from their own serious health condition without financial ruin. Spanberger has until April 13 to act.', '2026-03-25', 'news', '{"paid family leave","PFML","parental bonding","employee benefits","Virginia employment law","working parents"}', 'WSET — Virginia bill to create paid leave program awaits action from Gov. Spanberger', 'https://wset.com/news/local/virginia-bill-to-create-paid-leave-program-awaits-action-from-gov-spanberger-politics-va-business-economy-money-health-march-2026', NULL, NULL, NULL, 'paid family leave PFML parental bonding employee benefits Virginia employment law working parents news', FALSE),
  (130, 'US Divorce Rate Continues Gradual Decline in 2026: Key Statistics and Trends', 'A comprehensive Marble.co report published December 31, 2025 (circulating as the authoritative 2026 landscape analysis) synthesizes federal vital statistics data and shows the national crude divorce rate held at 2.4 per 1,000 people in 2023 across 45 reporting states and D.C., while the refined divorce rate (divorces per 1,000 married women) edged down again to 14.2 in 2024 from 14.4 in 2023. The marriage-to-divorce ratio rose to 2.42 nationally in 2024. The gray divorce rate (adults 50+) has plateaued at 10.3 per 1,000 married women after peaking at 11.0 in 2008. Divorce has fallen sharply among younger adults (women 15-24 from 46 to 18 per 1,000 since 1990) while older-adult divorce stabilized at elevated levels. Median first-marriage ages are now approximately 30 (men) and 28-29 (women). State variation is significant: Oklahoma (20.7) and Nevada (19.9) lead in refined divorce rates; Maine (10.0) and Wisconsin (10.8) are lowest. Virginia data is not directly reported but reflects mid-range Southern state patterns.', '2025-12-31', 'studies', '{"divorce rate","divorce statistics","gray divorce","national trends","marriage statistics","refined divorce rate","2026"}', 'Marble — State of Divorce in the US 2026', 'https://www.marble.co/blog/general/divorce/state-of-divorce-in-the-us-2026-the-numbers-behind-a-changing-institution', NULL, NULL, NULL, 'divorce rate divorce statistics gray divorce national trends marriage statistics refined divorce rate 2026 studies', FALSE),
  (131, 'SCOTUS Mirabelli v. Bonta (March 2, 2026): Landmark Parental Rights Ruling on School Gender Transition Disclosure', 'Although decided on March 2, 2026 — just outside this week''s window — the Supreme Court''s 6-3 ruling in Mirabelli v. Bonta continues to generate significant commentary and legal analysis through the week of March 22-26. The per curiam majority reinstated a class-action permanent injunction prohibiting California schools from concealing children''s gender social transitions from their parents without parental consent, holding that California''s nondisclosure policies likely violate the Free Exercise Clause and the Due Process Clause''s parental rights protections. The majority held that parents — not the State — hold ''primary authority with respect to the upbringing and education of children,'' including ''the right not to be shut out of participation in decisions regarding their children''s mental health.'' Justice Kagan, joined by Justice Jackson, dissented, arguing the majority misused the emergency docket. Justice Barrett (joined by Roberts and Kavanaugh) concurred, emphasizing the preliminary nature of the ruling. Justice Sotomayor would have denied both the parents'' and teachers'' applications; Justices Thomas and Alito would have also granted teachers'' relief. The decision is expected to affect school policy nationwide and may prompt Virginia school divisions to review their own gender identity notification policies.', '2026-03-02', 'scotus', '{"SCOTUS","Mirabelli v. Bonta","parental rights","gender transition","schools","Free Exercise","Due Process","children","disclosure"}', 'SCOTUSblog — Court sides with parents in dispute over California policies on transgender students', 'https://www.scotusblog.com/2026/03/divided-court-sides-with-parents-in-dispute-over-california-policies-on-transgender-students/', 'Mirabelli v. Bonta, No. 24A__ (U.S. Mar. 2, 2026) (per curiam)', 'Supreme Court of the United States', NULL, 'SCOTUS Mirabelli v. Bonta parental rights gender transition schools Free Exercise Due Process children disclosure scotus Supreme Court of the United States', FALSE),
  (132, 'Domestic Relations: Husband waited too long to claim entitlement to marital home', 'Where the circuit court entered a final order of divorce in 2019, and it did not retain jurisdiction to adjudicate equitable distribution, the circuit court lacked jurisdiction to consider husband''s claim to the marital home that was brought more than 21 days from entry of the 2019 divorce order. Case: Gonzalez v. Sarmiento, Record No. 2002-23-4. Court of Appeals of Virginia (unpublished opinion) (Ortiz). From the Circuit Court of Fairfax County (Carroll). Sept. 9, 2025.', '2025-09-22', 'case_law', '{"equitable distribution","jurisdiction","marital home","divorce decree","Rule 1:1","final order","Fairfax County"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2025/09/22/domestic-relations-husband-waited-too-long-to-claim-entitlement-to-marital-home/', 'VLW 025-7-247', 'Court of Appeals of Virginia', NULL, 'equitable distribution jurisdiction marital home divorce decree Rule 1:1 final order Fairfax County case_law Court of Appeals of Virginia', FALSE),
  (133, 'Domestic Relations: Husband''s company is marital property worth $800,000', 'Where the circuit court did not err when it found the husband''s company was marital property worth $800,000, its decision was affirmed. El Mehdi Marhoum argued that the court misapplied Code § 20-107.3, improperly credited expert testimony valuing Benel Solutions LLC at $800,000, disregarded equitable-distribution factors, adopted an impossible payment timeline, and wrongfully awarded wife all attorney''s fees. The court rejected challenges to the expert valuation (rounding, EIDL loan omission, dated sources), found classification under Code § 20-107.3(A)(3)(e) resulted in harmless error, and affirmed the attorney''s fee award. Marhoum v. Fekkak, Record No. 0643-24-4. Court of Appeals of Virginia (unpublished) (Raphael). From Circuit Court of Loudoun County (Fisher). Aug. 19, 2025.', '2025-09-02', 'case_law', '{"equitable distribution","business valuation","marital property","separate property","commingling","attorney's fees","Code § 20-107.3","Loudoun County"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2025/09/02/domestic-relations-husbands-company-is-marital-property-worth-800000/', 'VLW 025-7-223', 'Court of Appeals of Virginia', NULL, 'equitable distribution business valuation marital property separate property commingling attorney''s fees Code § 20-107.3 Loudoun County case_law Court of Appeals of Virginia', FALSE),
  (134, 'Domestic Relations: Court resolves couple''s dispute over real property', 'Where the husband failed to show that certain real property was purchased wholly with his separate funds, it was part of the marital estate subject to equitable distribution. The Norfolk City Circuit Court awarded wife sole possession of the Bayville property (subject to buyout of husband''s half interest within 90 days), divided retirement and investment accounts equally, ordered the sailboat sold, and awarded wife $1,000/month spousal support for up to 10 years. Husband was required to maintain wife as beneficiary on life insurance while support obligation remains. Greblunas v. Greblunas, CL24-76. Norfolk City Circuit Court (Lannetti). Aug. 11, 2025.', '2025-08-25', 'case_law', '{"equitable distribution","marital property","separate property","real property","spousal support","approbation and reprobation","tenancy by entirety","Norfolk"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2025/08/25/domestic-relations-court-resolves-couples-dispute-over-real-property/', 'VLW 025-8-029', 'Norfolk City Circuit Court', NULL, 'equitable distribution marital property separate property real property spousal support approbation and reprobation tenancy by entirety Norfolk case_law Norfolk City Circuit Court', FALSE),
  (135, 'Domestic Relations: Wife waited too long to challenge reason for divorce', 'Where the wife argued that she should have been granted a divorce on grounds of husband''s adultery, instead of based on the one-year separation as granted by the circuit court, but she failed to timely appeal the divorce decision, the appellate court lacked jurisdiction to consider the issue. The court also affirmed the equitable distribution award (wife waived personal property claims by conceding they had been dealt with), denied retroactive pendente lite spousal support (no evidence of need), and upheld the attorney''s fee award to husband. Sweeney-Fagan v. Fagan, Record No. 2257-23-4. Court of Appeals of Virginia (unpublished) (Chaney). From Circuit Court of Loudoun County (Fleming Jr.). July 15, 2025.', '2025-07-28', 'case_law', '{"divorce grounds","adultery","jurisdiction","Rule 1:1","equitable distribution","spousal support","pendente lite","attorney's fees","Loudoun County","approbation and reprobation"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2025/07/28/domestic-relations-wife-waited-too-long-to-challenge-reason-for-divorce/', 'VLW 025-7-184', 'Court of Appeals of Virginia', NULL, 'divorce grounds adultery jurisdiction Rule 1:1 equitable distribution spousal support pendente lite attorney''s fees Loudoun County approbation and reprobation case_law Court of Appeals of Virginia', FALSE),
  (136, 'Domestic Relations: Circuit court erred when it distributed marital home', 'Where the circuit court awarded husband a lump sum award calculated as half the value of the couple''s combined ownership interests in the marital home, it erred. A premarital agreement explicitly foreclosed any award to husband based on wife''s separate ownership interest in the marital home, regardless of any contributions made by husband. The home was titled as tenancy in common with husband owning 3% and wife 48.5%. The court reversed the $297,506 lump sum award, holding that the premarital agreement''s plain terms controlled — the circuit court could not award husband more than his 3% titled interest based on his contributions. Bethel v. Bethel, Record No. 1063-23-4. Court of Appeals of Virginia (Bernhard). From Circuit Court of Arlington County (DiMatteo). June 24, 2025.', '2025-07-13', 'case_law', '{"premarital agreement","equitable distribution","marital home","separate property","tenancy in common","lump sum award","Arlington County","contract interpretation"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2025/07/13/domestic-relations-circuit-court-erred-when-it-distributed-marital-home/', 'VLW 025-7-156', 'Court of Appeals of Virginia', NULL, 'premarital agreement equitable distribution marital home separate property tenancy in common lump sum award Arlington County contract interpretation case_law Court of Appeals of Virginia', FALSE),
  (137, 'VSB Discipline: Taso Rashid Noel Saunders — Six-Month Suspension', 'Effective March 27, 2026, the Virginia State Bar Disciplinary Board suspended Taso Rashid Noel Saunders''s license to practice law in the Commonwealth of Virginia for six months. The action was posted to the VSB disciplinary actions page on March 27, 2026. The VSB has not publicly disclosed the specific Rules of Professional Conduct violated or Saunders''s primary practice area in the publicly available summary. This is the only new suspension posted since March 25, 2026.', '2026-03-27', 'attorney_discipline', '{"VSB","suspension","attorney discipline","Virginia State Bar Disciplinary Board"}', 'Virginia State Bar Disciplinary System Actions', 'https://vsb.org/Site/Site/news/disciplinary-actions.aspx', NULL, NULL, NULL, 'VSB suspension attorney discipline Virginia State Bar Disciplinary Board attorney_discipline', FALSE),
  (138, 'Virginia General Assembly Elects New JDR and Circuit Court Judges — Ten New JDR Judges Starting in 2026', 'Virginia Lawyers Weekly published on March 30, 2026 the complete list of judges elected by the General Assembly in mid-March, including ten new judges to Virginia''s juvenile and domestic relations (JDR) district courts statewide. New JDR judges include Wilfredo Bonilla Jr. (1st District, term begins April 1), Lisa W. Piper and Terrica M. Taylor (12th District), William B. Hubbard and Crystal L. Montague-Holland (15th District, the state''s largest J&DR court), Tanishka V. Cruz (16th District), Maana K. Parcham (18th District), Timothy M. Fisk (22nd District), Elizabeth Heather H. Goodwin (24th District), and Jonathan E.P. Arnold (28th District). Several terms begin April 1, 2026. The elections were conducted by joint Senate and House resolutions passed unanimously on March 13.', '2026-03-30', 'news', '{"JDR court","juvenile domestic relations","new judges","Virginia courts","judicial election"}', 'Virginia Lawyers Weekly', 'https://valawyersweekly.com/2026/03/30/former-va-house-speaker-todd-gilbert-appointed-judge/', 'HJR315 / SR168, 2026 Regular Session', 'Juvenile and Domestic Relations District Courts (multiple districts)', NULL, 'JDR court juvenile domestic relations new judges Virginia courts judicial election news Juvenile and Domestic Relations District Courts (multiple districts)', FALSE),
  (139, 'Governor Spanberger Takes No Action on Pending Family Law Bills March 26–30 — April 13 Deadline Remains', 'As of March 30, 2026, Governor Spanberger has not signed, vetoed, or recommended amendments to any of the pending family law bills on her desk. Bills confirmed still awaiting action include: HB 942 (cannabis custody protections), HB 303 (fault divorce reform), HB 93 and SB 38 (protective order firearm transfers), HB 19 and SB 160 (intimate partner firearm loophole), HB 301 (adoptee birth certificates), HB 1207/SB 2 (paid family and medical leave), and HB 5/SB 199 (paid sick leave). All enrolled bills were communicated to the Governor on or before March 17, 2026, and the Governor''s action deadline for all legislation passed during the 2026 regular session is 11:59 p.m. on April 13, 2026. Governor''s office March 26–27 releases covered only a Tuskegee Airmen Commemoration Day proclamation and a seafood industry grant — no legislative actions.', '2026-03-30', 'virginia_code', '{"HB 942","HB 303","HB 93","SB 38","HB 19","SB 160","HB 301","HB 1207","SB 2","HB 5","SB 199","Governor action","Spanberger","April 13 deadline"}', 'Virginia Legislative Information System (LIS)', 'https://lis.virginia.gov/bill-details/20261/HB942', NULL, NULL, NULL, 'HB 942 HB 303 HB 93 SB 38 HB 19 SB 160 HB 301 HB 1207 SB 2 HB 5 SB 199 Governor action Spanberger April 13 deadline virginia_code', FALSE);
