-- ──────────────────────────────────────────────────────────────────────────────
-- SCHEMA
-- ──────────────────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS updates (
  id           SERIAL PRIMARY KEY,
  title        TEXT NOT NULL,
  summary      TEXT,
  date         TEXT,
  category     TEXT,
  tags         TEXT[],
  source_name  TEXT,
  source_url   TEXT,
  citation     TEXT,
  court        TEXT,
  blog_credit  TEXT,
  search_tags  TEXT,
  pinned       BOOLEAN DEFAULT FALSE,
  created_at   TIMESTAMP DEFAULT NOW()
);

-- Full-text search index on title + summary
CREATE INDEX IF NOT EXISTS idx_updates_search
  ON updates USING gin(to_tsvector('english', coalesce(title,'') || ' ' || coalesce(summary,'')));

-- Category filter index
CREATE INDEX IF NOT EXISTS idx_updates_category ON updates(category);

-- Date sort index
CREATE INDEX IF NOT EXISTS idx_updates_date ON updates(date);

-- ──────────────────────────────────────────────────────────────────────────────
-- DATA (131 rows)
-- ──────────────────────────────────────────────────────────────────────────────
-- Truncate + reinsert for idempotent seeding
TRUNCATE TABLE updates RESTART IDENTITY CASCADE;


-- Reset sequence to max id + 1
SELECT setval('updates_id_seq', (SELECT MAX(id) FROM updates));
